export interface HelpArticle {
  id: string;
  title: string;
  body: string;
  category: string;
  keywords: string;
  pages: string[];
  }

export const HELP_ARTICLES: HelpArticle[] = [
  { id: "time-1", title: "⏱️ How to track time", body: "Track every hour so nothing falls through the cracks — and your invoices write themselves.\\n\\n## Logging time\\n\\nClick **New Entry** on the time tracking page, pick your **Client**, **Project**, and **Service**, enter your hours, and hit **Save**. Toggle **Billable** on for anything the client should see on an invoice.\\n\\n## Views\\n\\nSwitch between **Day**, **Week**, and **Month** views at the top — most people live in Week view.\\n\\n## Real-time tracking\\n\\nUse the inline timer on the time tracking page to clock in and out throughout the day. When you stop the timer, CherryWorks converts the elapsed time into a time entry automatically.\\n\\n💡 Pro tip: Keyboard shortcut **Alt+T** starts and stops the timer from the time tracking page.", category: "Time Tracking", keywords: "time track hours entry log cell grid week month day view keyboard shortcut", pages: ["/time","/"] },
  { id: "time-2", title: "⏲️ Using the floating timer", body: "Stop guessing how long things take — the inline timer runs in real time so your entries are accurate.\\n\\n## Starting the timer\\n\\nOn the time tracking page, select a **Project** from the dropdown, then click the **play button** to start. The timer runs inline on the page while you work.\\n\\n## Stopping and saving\\n\\nWhen you're done, click the timer to **Stop**. CherryWorks rounds to your configured increment and opens the new entry dialog — review the details and save.\\n\\n💡 Pro tip: Use **Alt+T** to quickly toggle the timer without reaching for the mouse.", category: "Time Tracking", keywords: "timer float widget start stop real-time duration automatic entry pulse running", pages: ["/time"] },
  { id: "time-3", title: "💰 Billable vs non-billable time", body: "Know what's revenue and what's overhead — billable time drives your invoices, non-billable tracks internal work.\n\n## Billable time\n\nAny entry marked **Billable** can appear on a client invoice. When you generate invoices from time entries, only billable hours are pulled in.\n\n## Non-billable time\n\nInternal meetings, admin work, and training should be marked non-billable. They still show in reports and utilization metrics, but they'll never reach a client invoice.\n\n## Defaults\n\nEach **Service** has a default billable setting — so if you always bill for \"Strategy Sessions,\" you won't have to toggle it manually every time.\n\n💡 Pro tip: Track non-billable time too — it's the only way to get accurate utilization rates.", category: "Time Tracking", keywords: "billable non-billable internal utilization rate percentage toggle switch client-facing", pages: ["/time"] },
  { id: "ts-1", title: "📋 Submitting timesheets", body: "Done for the week? Submit your timesheet so your manager can approve it and billing can roll.\n\n## How to submit\n\nMake sure you're on the right week, review your hours, then click **Submit Week** in the top-right. You'll confirm in a quick dialog and your entries lock until approved.\n\n## What happens next\n\nYour timesheet lands on the **Approvals** page for your admin. You'll get notified when it's approved or kicked back for edits.\n\n💡 Pro tip: Submit every Friday before you log off — it keeps billing on schedule and avoids Monday morning chasing.", category: "Timesheets", keywords: "submit timesheet week approve lock review Friday deadline notification confirm", pages: ["/time","/"] },
  { id: "ts-2", title: "✅ Approving timesheets (Admin)", body: "Review your team's hours and keep billing moving — approvals take seconds once you know the flow.\n\n## Reviewing submissions\n\nHead to the **Approvals** page to see all pending timesheets. Each card shows the team member, total hours, and billable breakdown. Click any card to drill into the individual entries.\n\n## Approving or rejecting\n\nHit **Approve** to lock the timesheet and make those hours available for invoicing. Hit **Reject** with a note if something needs fixing — the team member gets notified and can resubmit.\n\n💡 Pro tip: Approve in bulk by selecting multiple timesheets and clicking **Approve Selected**.", category: "Timesheets", keywords: "approve reject admin review bulk lock authorize invoicing pending queue notification reason", pages: ["/","/time"] },
  { id: "inv-1", title: "🧾 Generating invoices from time entries", body: "Turn approved hours into a polished invoice in under a minute — no copy-pasting required.\\n\\n## Quick generation\\n\\nGo to **Invoices** and click **Generate Invoice**. Select a **Client** and CherryWorks pulls all approved, uninvoiced billable hours for that client and builds line items automatically.\\n\\n## Customizing\\n\\nGroup entries by project, service, or date. Edit descriptions, adjust quantities, and add flat-fee line items before sending. You can also click **Create Blank Invoice** to start from scratch.\\n\\n💡 Pro tip: Use **Service** grouping for a clean, professional look — clients prefer seeing totals by deliverable rather than a daily log.", category: "Invoicing", keywords: "generate invoice create bill client time entries approved billable line items grouping draft send PDF", pages: ["/invoices"] },
  { id: "inv-2", title: "📊 Invoice statuses explained", body: "Every invoice follows a clear lifecycle so you always know where your money stands.\n\n## The statuses\n\n- **Draft** — Created but not sent. Edit freely.\n- **Sent** — Delivered to the client. The clock starts on payment terms.\n- **Viewed** — The client opened the invoice (tracked automatically).\n- **Partial** — Some payment received, balance remaining.\n- **Paid** — Fully settled. Nothing left outstanding.\n- **Overdue** — Past the due date with an unpaid balance.\n- **Void** — Cancelled. Doesn't affect your books.\n\n💡 Pro tip: Filter by **Overdue** on the Invoices page to catch stragglers before they age.", category: "Invoicing", keywords: "status draft sent paid partial void overdue badge lifecycle filter color-coded counter due date", pages: ["/invoices"] },
  { id: "inv-3", title: "🌍 Multi-currency invoicing", body: "Bill international clients in their currency while your books stay in yours.\\n\\n## Setting it up\\n\\nSet each client's **Billing Currency** in their profile. When you create an invoice for that client, CherryWorks automatically uses their currency.\\n\\n## Exchange rates\\n\\nRates are pulled automatically or you can set a manual rate per invoice. Your **Dashboard** and **Reports** convert everything back to your base currency for consolidated views.\\n\\n💡 Pro tip: Lock the exchange rate on the invoice at send time — it prevents surprises if the rate shifts before payment.", category: "Invoicing", keywords: "currency multi exchange rate EUR GBP CAD AUD billing international consolidated base convert 30 currencies", pages: ["/invoices","/clients"] },
  { id: "inv-4", title: "📧 Sending invoices by email", body: "Send professional invoices straight from CherryWorks — no attachments or external email needed.\\n\\n## Sending\\n\\nOpen any invoice and click **Send**. The client gets an email with a **PDF attachment** and a **secure payment link**. You can customize the email subject and message before sending.\\n\\n## Requirements\\n\\nMake sure your **SMTP settings** are configured in **Settings** → **Accounting & Email** — without them, no emails go out.\\n\\n## Tracking\\n\\nOnce sent, the status flips to **Sent** and you can track when the client opens it.\\n\\n💡 Pro tip: Use the built-in payment link — clients who can pay online pay 2x faster than check-based workflows.", category: "Invoicing", keywords: "send email pdf attachment client SMTP portal online pay now Stripe deliver compose", pages: ["/invoices"] },
  { id: "pay-1", title: "💵 Recording a payment", body: "Keep your books accurate by recording every payment the moment it arrives.\n\n## Recording\n\nOpen the invoice and click **Record Payment**. Enter the amount, payment date, and method (check, ACH, wire, or cash). For partial payments, enter just the amount received — CherryWorks tracks the remaining balance.\n\n## What happens\n\nThe invoice status updates automatically (Partial or Paid), and if auto-posting is on, a GL journal entry posts to clear Accounts Receivable.\n\n💡 Pro tip: Record payments the same day they clear your bank — it keeps your AR aging report honest.", category: "Payments", keywords: "record payment receive money collect ACH check wire Stripe partial invoice balance reference manual", pages: ["/payments"] },
  { id: "pay-2", title: "💳 Stripe Checkout payments", body: "Let clients pay invoices online with a card — you get paid faster with zero chasing.\\n\\n## How it works\\n\\nConnect **Stripe** in **Settings** → **Billing & Invoicing**. Every invoice you send includes a **Pay Now** button. Clients click it, enter their card, and the payment records automatically.\\n\\n## Fees\\n\\nStripe's standard processing fees apply. Payments reconcile against the invoice instantly — no manual recording needed.\\n\\n💡 Pro tip: Enable Stripe Checkout on every invoice — firms that offer online payment collect 40% faster on average.", category: "Payments", keywords: "stripe online checkout automatic webhook pay now credit card ACH bank transfer PCI security fees onboarding connect", pages: ["/payments","/invoices"] },
  { id: "exp-1", title: "🧾 Creating an expense", body: "Capture expenses as they happen so nothing gets lost between the receipt and the books.\\n\\n## Adding an expense\\n\\nClick **New Expense**, choose your **Category**, enter the amount, date, and **Vendor** name. Mark it **Billable** if the client should reimburse it, and attach a receipt photo or PDF.\\n\\n## AI receipt scanning\\n\\nUpload a receipt image and CherryWorks extracts the vendor, amount, and date automatically — just review and confirm.\\n\\n💡 Pro tip: Snap receipts on your phone and upload them immediately — waiting until month-end means lost receipts and missed deductions.", category: "Expenses", keywords: "create expense vendor receipt upload category project billable reimbursable notes draft submit amount date", pages: ["/expenses"] },
  { id: "exp-2", title: "✔️ Expense approval workflow", body: "Keep spending under control — every expense goes through approval before it hits your books.\n\n## The flow\n\nTeam members submit expenses → an admin reviews them on the **Approvals** page → approved expenses post to the GL and queue for reimbursement if applicable.\n\n## Approving or rejecting\n\nClick any pending expense to review the details, receipt, and category. Hit **Approve** or **Reject** with an optional note.\n\n💡 Pro tip: Review expenses weekly — a backlog of unreviewed expenses creates bottlenecks at month-end close.", category: "Expenses", keywords: "submit approve reject reimburse payout workflow draft submitted approved rejected review admin GL journal entry", pages: ["/expenses"] },
  { id: "exp-3", title: "📦 Expense Reports", body: "Pull a clean summary of all expenses by team member, category, or date range — perfect for client billing and tax prep.\n\n## Running a report\n\nGo to **Reports** → **Expense Report**. Filter by date range, team member, category, or billable status. The report shows totals, averages, and a detailed line-item breakdown.\n\n## Exporting\n\nClick **Export CSV** to download the full report for your accountant or expense management system.\n\n💡 Pro tip: Run the expense report monthly and share it with your CPA — it saves hours during tax season.", category: "Expenses", keywords: "batch report group submit approve reject reimburse expense report package bundle lock GL journal entries reimbursed", pages: ["/expense-reports","/expenses"] },
  { id: "exp-4", title: "🤖 Receipt upload and AI scanning", body: "Ditch manual data entry — upload a receipt and let AI do the heavy lifting.\n\n## How it works\n\nDrag a receipt image or PDF into the expense form. CherryWorks uses AI to extract the **vendor name**, **amount**, **date**, and **category** — all pre-filled for your review.\n\n## Accuracy\n\nAI gets it right most of the time, but always double-check the extracted values before saving. You can override any field.\n\n💡 Pro tip: Take photos with good lighting and a flat background — the AI reads clean images much more accurately.", category: "Expenses", keywords: "receipt upload scan AI OCR auto-fill vendor date amount tax category vision image JPG PNG photo extract automatic", pages: ["/expenses"] },
  { id: "po-1", title: "💸 How payouts work", body: "Pay your team members accurately and on time — CherryWorks tracks every dollar from invoice to payout.\\n\\n## Auto-generated payouts\\n\\nWhen you send an invoice that includes a team member's billable hours, CherryWorks automatically calculates their payout based on their bill rate and pay rate. Payouts appear on the **Payouts** page.\\n\\n## Completing a payout\\n\\nReview the payout details, then click **Pay** to send the payment. For batch processing, use **Pay All Pending** to settle everything at once. You can also use **Record Payment** to log an external payment manually.\\n\\n💡 Pro tip: Batch payouts weekly or bi-weekly to reduce transaction overhead and keep your team happy.", category: "Payouts", keywords: "payout team member pay 1099 cost rate auto-generate pending completed W-2 excluded invoice send Corp-to-Corp GL", pages: ["/payouts"] },
  { id: "po-2", title: "💰 Expense reimbursement payouts", body: "Reimburse approved expenses quickly — your team shouldn't have to wait for money they've already spent.\n\n## How it works\n\nWhen an expense is approved and marked as **Reimbursable**, it queues for reimbursement. Head to **Payouts** to see pending reimbursements alongside regular payouts.\n\n## Processing\n\nClick the reimbursement, verify the amount, and mark it paid. The GL posts a clearing entry against **Accrued Employee Reimbursable** (2200).\n\n💡 Pro tip: Reimburse expenses within two weeks of approval — it builds trust and keeps your team from floating costs.", category: "Payouts", keywords: "reimburse expense payout auto approve reimbursable toggle amount linked GL journal entry cash weekly batch", pages: ["/payouts","/expenses"] },
  { id: "proj-1", title: "📁 Setting up a project", body: "Projects tie everything together — time, invoices, budgets, and profitability in one place.\n\n## Creating a project\n\nClick **New Project**, give it a name, assign a **Client**, set the **Budget Type** (fixed-fee, time & materials, or retainer), and add team members with their roles and rates.\n\n## Budget tracking\n\nAs time gets logged and expenses are recorded, CherryWorks tracks spend against your budget in real time. You'll see a clear progress bar and get alerts when you're approaching the limit.\n\n💡 Pro tip: Set up projects before logging any time — retroactively assigning entries to projects is tedious.", category: "Projects", keywords: "project create setup budget team rate bill cost client assignment services start end date member", pages: ["/projects"] },
  { id: "proj-2", title: "📈 Project profitability", body: "See exactly how profitable each project is — revenue minus costs, updated in real time.\n\n## The profitability view\n\nOpen any project and check the **Profitability** tab. It shows total revenue (from invoiced amounts), total costs (team payouts + expenses), and your margin as both a dollar figure and percentage.\n\n## Drilling down\n\nBreak down costs by team member to see who's driving value and where overruns are happening.\n\n💡 Pro tip: Check profitability before scoping similar future projects — past data is your best estimator.", category: "Projects", keywords: "profitability margin revenue cost labor expense profit percentage command center engagement scope rates monthly", pages: ["/projects"] },
  { id: "cl-1", title: "🔗 Client portal", body: "Give clients a self-service window into their account — fewer status emails, more trust.\n\n## What clients see\n\nEach client gets a secure portal showing their **invoices**, **estimates**, and **payment history**. They can view PDFs, accept estimates, and pay invoices online.\n\n## Sharing the link\n\nThe portal link is included in every invoice and estimate email. Clients can also bookmark it for future access.\n\nWhen a marketing prospect is ready to sign on, see **Marketing contacts overview** for how to convert them into a billable client.\n\n💡 Pro tip: Mention the portal during onboarding — clients who use it send fewer \"where's my invoice?\" emails.", category: "Clients", keywords: "portal client link self-service invoices payment history balance PDF download Stripe online no login shareable URL", pages: ["/clients"] },
  { id: "cl-2", title: "💱 Setting client currency", body: "International clients should see invoices in their own currency — you set it once and forget it.\n\n## Setting the currency\n\nOpen the client's profile and select their **Billing Currency**. Every invoice you create for that client will use this currency automatically.\n\n## Reporting\n\nAll amounts convert back to your **Base Currency** in reports and on the dashboard, so your consolidated view stays clean.\n\n💡 Pro tip: Set the billing currency when you first create the client — changing it later doesn't retroactively update existing invoices.", category: "Clients", keywords: "currency billing client edit international local USD EUR GBP CAD AUD JPY CHF base convert 30 currencies profile dropdown", pages: ["/clients"] },
  { id: "rep-1", title: "📊 Available reports", body: "Every report you need to run your firm is built in — no spreadsheet gymnastics required.\n\n## Report types\n\nCherryWorks includes reports for **Revenue**, **AR Aging**, **Expense**, **Utilization**, **WIP (Work in Progress)**, **Payout Summary**, **1099 Totals**, and **Project Profitability**. Each report has date filters, export options, and drill-down capabilities.\n\n## Accessing reports\n\nAll reports live under **Reports** in the sidebar. Pick the one you need, set your date range, and go.\n\nFor send-side metrics like opens, clicks, and bounces, see **Review send results** in the Marketing category.\n\n💡 Pro tip: Bookmark your three most-used reports — for most firms that's AR Aging, Revenue, and Utilization.", category: "Reports", keywords: "reports available categories list financial receivables operations team payouts expenses 20 built-in AR aging utilization WIP", pages: ["/reports"] },
  { id: "rep-2", title: "📥 Exporting reports to CSV", body: "Get your data out of CherryWorks and into any spreadsheet, accounting tool, or BI platform.\n\n## Exporting\n\nEvery report page has an **Export CSV** button in the top-right. Click it and your browser downloads a clean CSV with all the data currently displayed (respecting any active filters).\n\n## What's included\n\nThe CSV includes all columns visible on the report — amounts, dates, client names, categories, and totals.\n\n💡 Pro tip: Export before month-end close and share the CSV with your accountant — it's the easiest handoff possible.", category: "Reports", keywords: "export csv download spreadsheet Excel Google Sheets offline analysis date range filter column headers all reports", pages: ["/reports"] },
  { id: "team-1", title: "👥 Inviting team members", body: "Grow your team in CherryWorks — each person gets their own login, rate, and permissions.\n\n## Sending an invite\n\nGo to **Team** and click **Invite Team Member**. Enter their email, set their **Role** (Admin, Manager, or Team Member), **Worker Type** (W-2, 1099, or C2C), and their **Bill Rate** and **Pay Rate**.\n\n## What they receive\n\nThey'll get an email with a link to set their password and log in. Once in, they can track time, submit timesheets, and log expenses.\n\nWhich roles see the Marketing section depends on your firm's permissions — see **Tour of the Marketing section** for the role-by-role breakdown.\n\n💡 Pro tip: Set rates at invite time — it saves an awkward \"we forgot to set your rate\" conversation later.", category: "Team", keywords: "invite team member team member employee email worker type cost bill rate onboarding wizard 1099 W-2 C2C credentials", pages: ["/team"] },
  { id: "team-2", title: "🏷️ Worker types explained", body: "Get the classification right up front — it affects payouts, taxes, and GL treatment for the entire engagement.\n\n## W-2 Employee\n\nFull-time staff on payroll. CherryWorks doesn't generate payouts for W-2s since your payroll provider handles that.\n\n## 1099 Independent\n\nFreelancers and independent team members. CherryWorks auto-generates payouts when you invoice their work, and they'll need a 1099-NEC at year-end.\n\n## C2C (Corp-to-Corp)\n\nTeam members operating through their own business entity. Same payout mechanics as 1099, but no 1099-NEC filing required.\n\n💡 Pro tip: Consult your CPA before classifying anyone — one misclassification can trigger IRS penalties.", category: "Team", keywords: "1099 w2 c2c worker type team member employee corp-to-corp onboarding payout classification NEC tax IRS payroll Gusto ADP", pages: ["/team"] },
  { id: "set-1", title: "🏦 Base currency", body: "Your base currency is the foundation of all financial reporting — set it to match your primary bank account.\\n\\n## Setting it\\n\\nGo to **Settings** → **Billing & Invoicing** and select your **Base Currency** (USD, EUR, GBP, CAD, etc.).\\n\\n## What it affects\\n\\nAll multi-currency invoices and payments convert back to this currency for your **Dashboard**, **Reports**, and **GL**. Individual clients can have different billing currencies — the base currency only affects internal reporting.\\n\\n💡 Pro tip: Match your base currency to your bank account's primary currency to avoid confusion during reconciliation.", category: "Settings", keywords: "base currency settings default USD EUR GBP CAD billing primary operating consolidated reporting convert bank", pages: ["/settings"] },
  { id: "set-2", title: "📮 Email and SMTP setup", body: "Configure your outgoing email so CherryWorks can send invoices, reminders, and invitations on your behalf.\\n\\n## Quick setup\\n\\nIn **Settings** → **Accounting & Email**, enter your **SMTP Host**, **Port** (typically 587), **Username**, and **Password**. Click **Test Email** to verify.\\n\\n## What it powers\\n\\nOnce configured, CherryWorks uses your SMTP server for invoice delivery, estimate delivery, team invitations, and payment reminders.\\n\\nFor outbound marketing campaigns, sender configuration lives separately under **Set up your sender identity**.\\n\\n💡 Pro tip: Use a dedicated email like billing@yourfirm.com — it looks professional and keeps invoice emails separate from personal mail.", category: "Settings", keywords: "email SMTP host port setup configure send outgoing test TLS SSL Gmail Office365 password app-specific invoices reminders invitations", pages: ["/settings"] },
  { id: "imp-1", title: "📦 Importing data from other platforms", body: "Migrate your existing data into CherryWorks from 8 supported platforms — no re-entry required.\n\n## Supported platforms\n\nFreshBooks, QuickBooks, Harvest, Xero, Wave, BigTime, Scoro, and Paymo — each with its own branded import card.\n\n## How to import\n\nSelect your platform, choose the data type (Clients, Services, Invoices, Expenses, etc.), upload your CSV or Excel export, and let the wizard auto-map columns. Run a **Dry Run** first to preview, then **Execute Import** when you're satisfied.\n\n## Safety net\n\nEvery import has a **Rollback** button if something doesn't look right.\n\nMarketing contacts use a separate importer at **Marketing → Contacts → Import**; see **Import marketing contacts** for the recipient-side flow.\n\n💡 Pro tip: Always dry-run first, especially for large datasets — it catches mapping issues before they affect live data.", category: "Import", keywords: "import migrate freshbooks quickbooks harvest xero wave bigtime scoro paymo data brand color 8 platforms GL opening balances projects CSV Excel upload dry-run rollback", pages: ["/","/import"] },
  { id: "gs-1", title: "🚀 Getting started guide", body: "Get your firm set up in CherryWorks in about 30 minutes — here's the fastest path from signup to first invoice.\n\n## The essentials\n\nComplete these in order: **Firm Setup** (company name, logo, address) → **Services** (your service catalog with rates) → **First Client** (name, contact, billing currency) → **Invite Team** (emails, roles, rates) → **First Invoice**.\n\n## Tracking progress\n\nThe **Getting Started** page shows a progress tracker with green checkmarks as you complete each step. You can revisit any step anytime.\n\nIf you're on the Business or Enterprise plan, the Marketing OS add-on is also live — see **What is Marketing OS** for the four Foundations articles.\n\n💡 Pro tip: Bookmark the Getting Started page during your first week — it's the fastest way to find what you need.", category: "Getting Started", keywords: "getting started setup wizard guide onboarding 5 steps firm services client team invoice progress tracker", pages: ["/","/getting-started"] },
  { id: "gl-1", title: "📒 Chart of Accounts", body: "Your Chart of Accounts is the backbone of your books — every transaction flows through these accounts.\n\n## Getting started\n\nClick **Seed Default Accounts** to create 18 standard accounts covering assets, liabilities, equity, revenue, and expenses. That's enough for most firms right out of the box.\n\n## Customizing\n\nNeed something specific? Click **Add Account** and set the number, name, type, and normal balance. To hide an account you no longer use, click **Archive** — it stays in historical data but disappears from active views.\n\n💡 Pro tip: Stick with the default chart unless you have specific requirements — 18 accounts covers most professional services firms.", category: "Accounting", keywords: "chart accounts seed default add edit archive account number type asset liability equity revenue expense debit credit custom 18 standard", pages: ["/gl/accounts"] },
  { id: "gl-2", title: "📗 General Ledger Report", body: "Your complete financial record — every debit and credit across all accounts for any date range.\n\n## Running the report\n\nUse the quick filters (**This Month**, **Last Quarter**, **Year to Date**, **Last Year**) or set a custom date range. Only accounts with activity in the period are shown.\n\n## Drilling down\n\nClick any account row to expand and see individual journal entry lines with date, source type, memo, debit, credit, and running balance. Color-coded headers make account types easy to scan.\n\n## Exporting\n\nHit **Export CSV** or **Print** for a formatted copy your accountant will love.\n\n💡 Pro tip: Export Year to Date at the end of each quarter — your accountant will thank you.", category: "Accounting", keywords: "general ledger report transactions date range filter expand CSV export print running balance color-coded headers subtotal grand totals account activity", pages: ["/gl/ledger"] },
  { id: "gl-3", title: "📝 Journal Entries", body: "Every financial event creates a journal entry — the building blocks of double-entry accounting.\n\n## Auto-generated entries\n\nCherryWorks creates entries automatically for invoices, payments, payouts, and expenses. Each has a colored source badge linking back to the original record.\n\n## Manual entries\n\nClick **New Journal Entry**, set the date and memo, then add debit and credit lines. Debits must equal credits before you can save — the form shows running totals in real time.\n\n💡 Pro tip: Use manual entries for adjustments like depreciation, accruals, and year-end closing — always include a clear memo.", category: "Accounting", keywords: "journal entry manual create debit credit balance auto-generated source badge expand filter Invoice Payment Payout Expense running totals adjustments", pages: ["/gl/journal-entries"] },
  { id: "gl-4", title: "⚖️ Trial Balance", body: "Verify your books are balanced in one glance — total debits must equal total credits.\n\n## Running it\n\nSet the **As-Of Date** and the report shows every account with a balance, grouped by type. Each group has a subtotal, and the grand total at the bottom shows whether you're balanced.\n\n## Reading the result\n\nGreen **Balanced** badge = you're good. Red **Out of Balance** badge = something needs investigating.\n\n💡 Pro tip: Run the trial balance before month-end close — catching imbalances early saves hours of detective work.", category: "Accounting", keywords: "trial balance as-of date debit credit balanced out of balance verify subtotal CSV export red green badge group accountant month-end", pages: ["/gl/trial-balance"] },
  { id: "gl-5", title: "⚙️ Auto-Journal Entries", body: "CherryWorks handles your bookkeeping automatically — five financial events trigger GL entries without any manual work.\\n\\n## The five triggers\\n\\n- **Invoice Sent** — Debits Accounts Receivable (1200), credits Service Revenue (4000)\\n- **Payment Received** — Debits Cash (1000), credits AR (1200)\\n- **Payout Completed** — Debits Team Payout Costs (5100), credits Cash (1000)\\n- **Expense Approved** — Debits the mapped expense account, credits Cash or Accrued Reimbursable\\n- **Expense Reimbursed** — Debits Accrued Reimbursable (2200), credits Cash (1000)\\n\\n## Error handling\\n\\nIf a GL posting fails, the core operation still succeeds — you can manually post later.\\n\\n💡 Pro tip: Enable auto-posting in **Settings** → **Accounting & Email** to keep your books current in real time.", category: "Accounting", keywords: "auto journal entry invoice payment payout expense trigger automatic hook five events debit credit accounts receivable revenue cash team payout costs reimbursable", pages: ["/gl/journal-entries","/gl/ledger","/gl/accounts"] },
  { id: "gl-6", title: "🔄 GL Migration", body: "Started using CherryWorks before enabling the GL? The one-time migration replays your history as journal entries.\n\n## Running the migration\n\nGo to **Chart of Accounts**, make sure your accounts are seeded, then click **Run GL Migration**. The system processes everything in chronological order: invoices, payments, payouts, and expenses.\n\n## Safety\n\nThe migration is **idempotent** — it won't run if entries already exist, so there's no risk of duplicates. Check the **Trial Balance** afterward to confirm everything is balanced.\n\n💡 Pro tip: Run the migration during off-hours when no one is actively creating invoices or recording payments.", category: "Accounting", keywords: "migrate migration replay historical data seed one-time import GL ledger chronological idempotent prevent duplicates trial balance verify", pages: ["/gl/accounts","/gl/ledger","/gl/journal-entries","/gl/trial-balance"] },
  { id: "wiz-1", title: "🧙 Implementation Wizard", body: "A hands-on, step-by-step setup flow that walks you through configuring your entire firm — with built-in validation at every step.\n\n## How it works\n\nThe wizard guides you through each setup phase with inline forms: firm details, services, clients, team members, and your first invoice. Each step validates your input before moving on.\n\n## Progress tracking\n\nYou'll see a visual progress bar showing completed and remaining steps. You can jump back to any previous step to make changes.\n\n💡 Pro tip: Use the wizard if you prefer guided setup — it's faster than finding each page manually.", category: "Getting Started", keywords: "implementation wizard getting started setup onboarding 5 step firm services client team invoice guided checkmark validation tooltip", pages: ["/getting-started"] },
  { id: "imp-2", title: "🔄 Competitor Data Import", body: "Switching from another platform? Import your data with column mapping and dry-run previews.\n\n## The workflow\n\nPick your source platform, choose the data type, upload your export file, and let the wizard auto-map columns to CherryWorks fields. Preview the results in a dry run before committing.\n\n## Rollback\n\nEvery import can be undone with a single click if something doesn't look right.\n\n💡 Pro tip: Export your data from the old platform right before importing — stale exports lead to missing recent records.", category: "Import", keywords: "import competitor freshbooks quickbooks xero harvest wave bigtime scoro paymo migrate data CSV Excel upload 7 step brand color 8 data types GL opening balances projects dry-run rollback verify", pages: ["/","/import"] },
  { id: "gs-2", title: "📖 Getting Started Guide", body: "Your onboarding hub — a structured path from zero to a fully configured firm.\n\n## What's covered\n\nFirm setup, service catalog, first client, team invitations, and your first invoice. Each step has a green checkmark once complete.\n\n## Flexibility\n\nYou can complete steps in any order and revisit any step at any time. For a more hands-on walkthrough, try the **Implementation Wizard** on the same page.\n\n💡 Pro tip: Bookmark this page during your first week — it's your fastest path to finding anything.", category: "Getting Started", keywords: "getting started onboarding new user setup guide progress track firm checkmark revisit bookmark wizard", pages: ["/","/getting-started"] },
  { id: "est-1", title: "📝 How estimates work", body: "Create professional quotes before starting work — and convert them into invoices with one click when the client says yes.\n\n## Creating an estimate\n\nClick **New Estimate**, select a **Client**, add line items with descriptions, quantities, and rates. Set an optional **Expiry Date** to create urgency.\n\n## The client experience\n\nClients receive an email with a PDF and a secure link where they can **Accept** or **Decline** online.\n\n## Converting to invoice\n\nOnce accepted, click **Convert to Invoice** — all line items carry over automatically into a new draft invoice.\n\n💡 Pro tip: Always include an expiry date — quotes without deadlines sit in client inboxes indefinitely.", category: "Estimates", keywords: "estimate quote create send accept decline convert invoice client proposal PDF public link expiry date line items notes terms", pages: ["/estimates"] },
  { id: "est-2", title: "🏷️ Estimate statuses", body: "Every estimate follows a clear lifecycle with color-coded badges so you know exactly where things stand.\n\n## The statuses\n\n- **Draft** (gray) — Not yet sent. Edit freely.\n- **Sent** (blue) — Delivered to the client.\n- **Accepted** (green) — Client approved. Ready to convert to invoice.\n- **Declined** (red) — Client passed. Follow up or revise.\n- **Invoiced** (purple) — Converted into an invoice.\n\n## Expiry\n\nEstimates can have an expiry date. After it passes, the estimate is flagged — but clients can still accept if they choose.\n\n💡 Pro tip: Follow up within 48 hours of a decline — often it's a scope or pricing issue that's easy to fix.", category: "Estimates", keywords: "status draft sent accepted declined invoiced expiry date lifecycle badge color-coded filter convert follow-up expired", pages: ["/estimates"] },
  { id: "rec-1", title: "🔁 Setting up recurring invoices", body: "Automate repetitive billing — set it once and CherryWorks generates invoices on schedule.\\n\\n## Creating a schedule\\n\\nOpen any invoice and click **Make Recurring**. Set the **Frequency** (weekly, monthly, quarterly, annually), **Start Date**, and optional **End Date**. CherryWorks creates new draft invoices automatically on each cycle.\\n\\n## Managing schedules\\n\\nView all active recurring schedules by clicking **Recurring** on the **Invoices** page. Pause, edit, or cancel any schedule at any time.\\n\\n💡 Pro tip: Set recurring invoices to auto-send — it eliminates the monthly \\\"did I send that invoice?\\\" question entirely.", category: "Billing", keywords: "recurring invoice template auto-generate frequency daily weekly biweekly monthly quarterly yearly pause resume start end date occurrences retainer automated", pages: ["/invoices/recurring"] },
  { id: "gl-7", title: "🔀 Auto-post vs manual GL posting", body: "You control whether GL entries post automatically or wait for your review — toggle it anytime.\\n\\n## Auto-post (recommended)\\n\\nTurn it on in **Settings** → **Accounting & Email**. GL entries post instantly when invoices are sent, payments recorded, expenses approved, and payouts completed.\\n\\n## Manual posting\\n\\nWith auto-post off, each page shows a **Post to GL** button next to unposted transactions. Items already posted display a green **Posted to GL** badge.\\n\\n💡 Pro tip: Start with auto-posting on — switch to manual only if you need to review transactions before they hit the ledger.", category: "Accounting", keywords: "auto-post manual GL toggle setting journal entries automatic button posted badge control invoice payment expense payout", pages: ["/settings","/gl/journal-entries"] },
  { id: "inv-5", title: "📋 Invoice line item grouping", body: "Group your invoice line items for a cleaner, more professional presentation.\n\n## Grouping options\n\nWhen importing time entries, choose to group by **Service**, **Project**, **Date**, or **Team Member**. Each group gets a subtotal, making the invoice scannable at a glance.\n\n## Custom groups\n\nYou can also manually drag line items into custom groups and label them however you want.\n\n💡 Pro tip: Group by **Service** for client-facing invoices — it focuses on deliverables, not timesheets.", category: "Invoicing", keywords: "group line item team member project service none consolidate generate invoice grouping dropdown transparency detail summary", pages: ["/invoices"] },
  { id: "mgmt-1", title: "✅ Approvals page", body: "One place to review everything that needs your sign-off — timesheets, expenses, and payout requests.\n\n## What shows up\n\nThe **Approvals** page aggregates all pending items across your org. Filter by type (Timesheet, Expense) or by team member to focus your review.\n\n## Taking action\n\nClick any item to review the details, then **Approve** or **Reject** with an optional note. Bulk actions let you approve multiple items at once.\n\n💡 Pro tip: Check approvals first thing Monday morning — it unblocks billing and payouts for the week.", category: "Management", keywords: "approvals pending timesheets review bulk approve reject admin queue grouped team member week expand verify lock eligible Monday", pages: ["/approvals"] },
  { id: "svc-1", title: "🛠️ Managing services", body: "Your service catalog defines what you sell — bill rates, default billable status, and descriptions all live here.\n\n## Adding a service\n\nGo to **Services** and click **Add Service**. Set the name, description, and default **Bill Rate**. Toggle **Billable by Default** for services that should always appear on invoices.\n\n## Editing and archiving\n\nEdit any service's details at any time. To retire a service, click **Archive** — it won't appear in dropdowns but stays in historical records.\n\n💡 Pro tip: Keep your service list focused — 5-10 well-defined services beats 50 vague ones every time.", category: "Services", keywords: "services catalog development design bill rate activate deactivate manage add edit name hourly project assignment dropdown catalog", pages: ["/services"] },
  { id: "dash-1", title: "🏠 Dashboard overview", body: "Your firm's vital signs at a glance — revenue, outstanding invoices, utilization, and cash flow.\n\n## Key metrics\n\nThe dashboard shows **Revenue this month**, **Outstanding AR**, **Overdue invoices**, **Team utilization**, and **Recent activity**. Everything updates in real time as transactions flow through.\n\n## Quick actions\n\nJump directly to **New Invoice**, **New Time Entry**, or **New Expense** from the dashboard without navigating through the sidebar.\n\nWhen Marketing OS is enabled, the dashboard also surfaces campaign engagement widgets — see **Tour of the Marketing section** for what shows up where.\n\n💡 Pro tip: Start every morning on the dashboard — it takes 10 seconds to know where your firm stands.", category: "Dashboard", keywords: "dashboard overview metrics revenue AR pending timesheets activity quick actions home KPI cards trend chart utilization role admin team member", pages: ["/","/dashboard"] },
  { id: "prof-1", title: "👤 Your profile page", body: "Manage your personal settings — name, email, password, avatar, and notification preferences.\n\n## Updating your profile\n\nClick your avatar in the top-right corner and select **Profile**. Update your **Name**, **Email**, **Password**, or upload a new **Avatar**.\n\n## Notifications\n\nControl which email notifications you receive — invoice sent confirmations, payment received alerts, timesheet reminders, and approval notifications.\n\n💡 Pro tip: Upload a professional headshot — it shows on invoices and the client portal, adding a personal touch.", category: "Profile", keywords: "profile earnings hours projects personal details avatar utilization active projects bill cost rate edit display name breakdown monthly verify", pages: ["/profile"] },
  { id: "inv-6", title: "🔔 Invoice payment reminders", body: "Automate the awkward follow-up — CherryWorks sends payment reminders so you don't have to.\\n\\n## Setting up reminders\\n\\nIn **Settings** → **Billing & Invoicing**, enable **Payment Reminders** and set the schedule (comma-separated days after the due date, e.g., 7, 14, 30).\\n\\n## How they work\\n\\nCherryWorks sends polite, professional emails to clients with a direct link to pay. You can customize the reminder message template.\\n\\n💡 Pro tip: Start with reminders at 7 and 14 days after the due date — that cadence catches most late payers without being annoying.", category: "Invoicing", keywords: "reminder overdue payment automatic email days interval due date pay now link template customize rate-limited toggle collection follow-up", pages: ["/invoices","/settings"] },
  { id: "bank-1", title: "🏦 Connecting a bank account", body: "Link your bank account to CherryWorks for automatic transaction import and reconciliation.\n\n## Connecting\n\nGo to **Banking** and click **Connect Bank Account**. Select your bank from the search, log in with your banking credentials through a secure connection, and select which accounts to sync.\n\n## Security\n\nCherryWorks uses read-only access — we can see transactions but never move money or modify your account.\n\n💡 Pro tip: Connect your primary operating account first — it's where most invoice payments land.", category: "Banking", keywords: "bank connect account stripe financial connections link institution checking savings business authorize read-only secure encrypted multiple", pages: ["/banking"] },
  { id: "bank-2", title: "🔃 Syncing bank transactions", body: "Keep your books current — bank transactions sync automatically and are ready to match within hours.\n\n## Auto-sync\n\nOnce connected, your bank transactions import automatically every few hours. You'll see new transactions appear in the **Banking** feed with status indicators.\n\n## Manual sync\n\nNeed the latest data now? Click **Sync Now** to trigger an immediate refresh.\n\n💡 Pro tip: Check the banking feed weekly — matching transactions in small batches is faster than a monthly marathon.", category: "Banking", keywords: "sync transactions import pull fetch bank automatic credit debit green red matching engine payments payouts daily current", pages: ["/banking"] },
  { id: "bank-3", title: "🔗 How transaction matching works", body: "CherryWorks intelligently matches bank transactions to your invoices, payments, and expenses — you just confirm.\n\n## Auto-matching\n\nThe system compares amounts, dates, and descriptions to find likely matches. When it's confident, it suggests a match with a confidence score.\n\n## Match types\n\n- **Invoice Payment** — Bank deposit matches a specific invoice\n- **Expense** — Bank charge matches a recorded expense\n- **Transfer** — Movement between your own accounts\n\n💡 Pro tip: The more consistently you record payments and expenses, the better auto-matching gets over time.", category: "Banking", keywords: "match auto-match payment payout credit debit confidence engine high medium low score amount date tolerance window direction-aware rules", pages: ["/banking"] },
  { id: "bank-4", title: "🔍 Reviewing and accepting matches", body: "Review suggested matches and confirm them with a click — or override the suggestion if it's wrong.\n\n## Reviewing\n\nEach suggested match shows the bank transaction alongside the CherryWorks record it matched to. Check the amounts, dates, and descriptions.\n\n## Accepting or overriding\n\nClick **Accept** to confirm the match, or **Change Match** to select a different record. You can also **Create New** if there's no existing record to match against.\n\n💡 Pro tip: Review matches in chronological order — it helps catch any transactions that were recorded out of sequence.", category: "Banking", keywords: "review accept reject match dialog confidence score high medium low payment payout entity type amount date badge matched reconciliation", pages: ["/banking"] },
  { id: "bank-5", title: "✅ Reconciling transactions", body: "Reconciliation proves your books match your bank — it's the final check that everything adds up.\n\n## The process\n\nSelect a bank account, set the **Statement End Date** and **Statement Balance**, then check off each transaction that appears on your bank statement.\n\n## Balancing\n\nAs you check transactions, the **Difference** counter counts down to zero. When it hits zero, you're reconciled — click **Complete** to lock it in.\n\n💡 Pro tip: Reconcile monthly, right after your bank statement posts — it catches errors while they're still fresh.", category: "Banking", keywords: "reconcile reconciliation batch walkthrough confirm match verify skip ignore green badge status selected one-click method", pages: ["/banking"] },
  { id: "bank-6", title: "📊 Banking reconciliation summary", body: "After reconciliation, get a clear summary showing everything that matched and anything still outstanding.\n\n## The summary\n\nThe reconciliation summary shows total **Cleared** transactions, **Outstanding** items (not yet on the statement), and the final **Reconciled Balance**.\n\n## Historical view\n\nAll past reconciliations are saved — click any completed period to review what was cleared and what carried forward.\n\n💡 Pro tip: Export the reconciliation summary as part of your month-end close package for your accountant.", category: "Banking", keywords: "summary dashboard cards total matched reconciled unmatched history log percentage count progress bird's-eye month-end bank fees interest", pages: ["/banking"] },
  { id: "bank-7", title: "👁️ Ignoring and restoring transactions", body: "Not every bank transaction belongs in your books — ignore the noise and keep your feed clean.\n\n## Ignoring\n\nPersonal transactions, duplicate entries, or irrelevant transfers? Click **Ignore** to hide them from the matching queue. Ignored transactions won't affect reconciliation.\n\n## Restoring\n\nChanged your mind? Go to the **Ignored** tab and click **Restore** to bring any transaction back into the active feed.\n\n💡 Pro tip: Ignore personal transactions on the day they appear — a clean feed makes monthly reconciliation painless.", category: "Banking", keywords: "ignore restore hide exclude irrelevant personal transaction pending eye-off icon walkthrough status filter ATM withdrawal transfer cluttering", pages: ["/banking"] },
  { id: "set-3", title: "🔢 Invoice and estimate prefixes", body: "Customize your numbering format so invoices and estimates match your firm's branding.\\n\\n## Setting prefixes\\n\\nIn **Settings** → **Billing & Invoicing**, set your **Invoice Prefix** (e.g., INV-, CW-) and **Estimate Prefix** (e.g., EST-, Q-). Numbers auto-increment from there.\\n\\n## Resetting\\n\\nYou can change the prefix anytime — existing documents keep their original numbers, and new ones use the updated format.\\n\\n💡 Pro tip: Use short prefixes (3-4 characters) — they look cleaner on invoices and in reports.", category: "Settings", keywords: "prefix invoice estimate number customize format branding initials auto-increment new documents billing defaults CW INV EST", pages: ["/settings"] },
  { id: "pay-3", title: "🏧 ACH bank transfer payments", body: "Accept ACH payments for lower fees and faster settlement than credit cards.\\n\\n## Enabling ACH\\n\\nIn **Settings** → **Billing & Invoicing**, enable **ACH Bank Transfer** through your Stripe account. Clients will see an ACH option alongside card payment on their invoice.\\n\\n## How it works\\n\\nClients enter their bank routing and account numbers. The payment takes 3-5 business days to settle. Once cleared, it records automatically against the invoice.\\n\\n💡 Pro tip: Offer ACH for invoices over $1,000 — the lower fees add up fast on bigger payments.", category: "Payments", keywords: "ACH bank transfer stripe lower fees direct debit clearing days routing account number webhook automatic 0.8% capped $5 credit card savings", pages: ["/invoices","/payments"] },
  { id: "po-3", title: "⚡ Stripe Connect team payouts", body: "Pay your team members instantly through Stripe Connect — no checks, no manual transfers.\\n\\n## Setting it up\\n\\nEach team member connects their Stripe account via a secure onboarding link from their profile. Once connected, you can send payouts directly through CherryWorks.\\n\\n## Processing a payout\\n\\nOn the **Payouts** page, click **Pay** next to any pending payout. Funds arrive in the team member's bank account within 1-2 business days.\\n\\n💡 Pro tip: Encourage all 1099 and C2C team members to connect Stripe — it's the fastest and most trackable payment method.", category: "Payouts", keywords: "stripe connect payout bank deposit direct onboarding status NOT_STARTED ACTIVE identity verification tax compliance GL transfer fast", pages: ["/payouts","/team"] },
  { id: "team-3", title: "🏷️ Worker classification (W-2, 1099, C2C)", body: "Classification determines how CherryWorks handles payouts, taxes, and GL entries for each team member.\n\n## W-2 Employees\n\nHandled by your payroll provider. No auto-payouts generated in CherryWorks. GL impact flows through payroll integration.\n\n## 1099 Independents\n\nAuto-payouts generated when you invoice their work. Pay via check, ACH, or Stripe Connect. A 1099-NEC is issued at year-end.\n\n## C2C (Corp-to-Corp)\n\nSame payout mechanics as 1099. No 1099-NEC required since they operate as a business entity.\n\n💡 Pro tip: Get classification right at hire time — it affects taxes, payouts, and GL structure for the entire engagement.", category: "Team", keywords: "worker classification W-2 1099 C2C employee team member corp type tax IRS penalties onboarding payroll Gusto ADP Rippling EIN W-9 bank", pages: ["/team"] },
  { id: "team-4", title: "🔌 Zapier and payroll webhooks", body: "Connect CherryWorks to your payroll system and other tools using webhooks and Zapier integration.\\n\\n## Webhooks\\n\\nIn **API & Integrations**, configure webhook URLs for events like **Team Member Added**, **Timesheet Approved**, and **Payout Completed**. CherryWorks sends a JSON payload to your endpoint when each event fires.\\n\\n## Zapier\\n\\nUse Zapier to connect CherryWorks to 5,000+ apps without code. Common workflows: sync approved timesheets to Gusto, send Slack alerts for new invoices, or push expenses to QuickBooks.\\n\\n💡 Pro tip: Start with a Slack notification for payments received — it's a morale boost for the whole team.", category: "Team", keywords: "zapier webhook payroll gusto ADP rippling API integration automate timesheet X-API-Key header events approved payout created team member payload", pages: ["/team","/settings"] },
  { id: "gs-3", title: "🎯 Mission Control command center", body: "Your command center for managing every active workstream — projects, invoices, team, and tasks in one view.\n\n## What's on Mission Control\n\nActive projects with status indicators, pending invoices, upcoming deadlines, and team workload at a glance. Everything is clickable — drill into any item for details.\n\n## Quick actions\n\nCreate new projects, invoices, or time entries directly from Mission Control without navigating away.\n\n💡 Pro tip: Pin Mission Control as your browser homepage — it's the best starting point for your workday.", category: "Getting Started", keywords: "mission control command center tabs setup discover tips quick actions wizard progress ring stats changelog feature cards shortcuts batch operations", pages: ["/getting-started"] },
  { id: "gs-4", title: "❓ Using CherryAssist and Knowledge Base", body: "Get answers instantly — CherryAssist is your AI guide, and the Knowledge Base has articles for everything.\n\n## CherryAssist\n\nClick the **chat icon** to ask questions in plain English. CherryAssist understands your context (which page you're on, what you're looking at) and gives targeted answers.\n\n## Knowledge Base\n\nPress **?** on any page to open the Knowledge Base. You'll see articles relevant to your current page, plus search across all 100+ articles.\n\n💡 Pro tip: Press **?** first — the contextual articles usually answer your question faster than typing it out.", category: "Getting Started", keywords: "cherryassist knowledge base help panel shortcut slash question mark search contextual AI chat article cards contact support browse category", pages: ["/","/getting-started","/time","/invoices","/expenses","/projects","/team","/reports","/settings","/payouts","/clients"] },
  { id: "rep-3", title: "📉 AR Aging report", body: "See exactly who owes you money and how long it's been outstanding — your most important collections tool.\n\n## Reading the report\n\nThe AR Aging report groups outstanding invoices into buckets: **Current**, **1-30 days**, **31-60 days**, **61-90 days**, and **90+ days**. Each client has a row showing their total balance across each bucket.\n\n## Taking action\n\nClick any amount to see the individual invoices behind it. Send reminders or follow up directly from the report.\n\n💡 Pro tip: Anything in the 61+ day buckets needs a phone call, not just another email.", category: "Reports", keywords: "AR aging accounts receivable overdue buckets 30 60 90 days donut chart collections drill down current outstanding past due export CSV", pages: ["/reports","/"] },
  { id: "rep-4", title: "📋 1099 team member totals and tax reporting", body: "Generate year-end 1099 totals for your independent team members — ready for tax filing.\n\n## The report\n\nThe 1099 report shows total payments made to each 1099 and C2C team member for the tax year. It includes their name, tax ID (if on file), and total amount paid.\n\n## Exporting\n\nExport the report as CSV and hand it to your accountant or import it into your tax filing software.\n\n💡 Pro tip: Run this report in early January — the filing deadline for 1099-NECs is January 31st.", category: "Reports", keywords: "1099 team member totals tax reporting year-end NEC export CSV compensation invoice payout expense reimbursement W-2 excluded January 31 IRS filing $600", pages: ["/reports","/team"] },
  { id: "rep-5", title: "📈 Utilization report", body: "Measure how effectively your team spends their time — the metric that separates profitable firms from struggling ones.\n\n## What it shows\n\nFor each team member: total hours, billable hours, non-billable hours, and **utilization rate** (billable / total). Filter by date range and team member.\n\n## Benchmarks\n\nMost professional services firms target 65-80% utilization. Below 60% means too much overhead; above 85% risks burnout.\n\n💡 Pro tip: Review utilization monthly with your team — it drives better time tracking habits and healthier workloads.", category: "Reports", keywords: "utilization billable hours percentage target team-member weekly monthly team green amber red color indicator capacity burnout non-billable export", pages: ["/reports"] },
  { id: "rep-6", title: "⏳ WIP and unbilled time report", body: "Track work that's been done but not yet invoiced — your unbilled revenue sitting on the table.\n\n## What it shows\n\nThe WIP report lists all approved billable time entries that haven't been included on an invoice yet, grouped by client and project. It shows hours, bill rates, and total unbilled value.\n\n## Why it matters\n\nHigh WIP means you're doing work but not getting paid. Review it weekly and invoice promptly.\n\n💡 Pro tip: Set a WIP target of under 2 weeks — anything older is money you should have billed already.", category: "Reports", keywords: "WIP work in progress unbilled time revenue leakage aging forecast invoice days value sort client project oldest highest dollar Friday weekly", pages: ["/reports"] },
  { id: "imp-3", title: "📥 Competitor data import details", body: "Each import platform has specific export formats and column mappings — here's what to know.\n\n## Export formats\n\nMost platforms export to CSV or Excel. Use the export function in your current platform to get the freshest data — don't use old exports.\n\n## Column mapping\n\nThe import wizard auto-maps most columns, but you may need to manually map custom fields. Preview the mapping in the dry-run step before committing.\n\n💡 Pro tip: Export data right before importing — stale exports miss recent transactions.", category: "Import", keywords: "import competitor quickbooks xero harvest wave bigtime scoro paymo CSV format mapping rollback dry-run brand color 8 data types GL projects order reference transactional", pages: ["/","/import"] },
  { id: "imp-5", title: "📂 Projects Import", body: "Bring your existing project structure into CherryWorks — names, clients, budgets, and team assignments.\n\n## What gets imported\n\nProject name, assigned client, budget type, budget amount, status, and team member assignments (if your export includes them).\n\n## After import\n\nReview each project to confirm client assignments and budget settings. Time entries can then be logged against imported projects immediately.\n\n💡 Pro tip: Import projects before importing time entries — it ensures entries have a project to attach to.", category: "Import", keywords: "projects import harvest bigtime scoro paymo PSA project data migrate budget hours client assignment start end date status CSV auto-map unresolved reference", pages: ["/import","/projects"] },
  { id: "manager-role", title: "🔑 What is the Manager role?", body: "Managers sit between Admins and Team Members — they can oversee their direct reports without seeing the full org.\n\n## What Managers can do\n\nApprove timesheets and expenses for their assigned team members, view project progress for their projects, and access reports scoped to their team.\n\n## What Managers can't do\n\nThey can't see billing details, org-wide financials, other managers' teams, or admin settings.\n\n💡 Pro tip: Use the Manager role for team leads and department heads who need oversight but not full admin access.", category: "Team & Roles", keywords: "manager role permissions access control operational admin team-member team invite settings billing payouts cost rate profitability refund void import rollback", pages: ["/team","/"] },
  { id: "mgr-1", title: "👔 Understanding the Manager role", body: "Managers bridge the gap between full admin access and basic team member permissions — scoped oversight for team leads.\n\n## Core capabilities\n\nManagers approve timesheets and expenses for their direct reports, track project progress for assigned projects, and access team-scoped reports.\n\n## Boundaries\n\nManagers don't see org-wide financials, other teams' data, billing settings, or admin configuration.\n\n💡 Pro tip: Assign the Manager role to anyone who needs to approve work but shouldn't see firm-wide financial data.", category: "Management", keywords: "manager role team lead oversight approve dashboard access permissions hierarchy team-member admin", pages: ["/","/team"] },
  { id: "mgr-2", title: "🔐 What Managers can and cannot see", body: "Manager visibility is carefully scoped — they see exactly what they need and nothing more.\n\n## Can see\n\nTimesheets and expenses for their assigned team members, projects they're assigned to, reports filtered to their team, and their own profile settings.\n\n## Cannot see\n\nOrg-wide revenue, all client billing details, other managers' teams, admin settings, API configuration, and import tools.\n\n💡 Pro tip: Review Manager assignments quarterly — as teams shift, their access scope should too.", category: "Management", keywords: "manager permissions visibility cost scrubbing financial data access control confidential margin rate", pages: ["/team"] },
  { id: "mgr-3", title: "⬆️ Promoting a team member to Manager", body: "Elevate a team member to Manager when they're ready to oversee a team — it takes 30 seconds.\n\n## How to promote\n\nOpen the team member's profile, change their **Role** from Team Member to **Manager**, then assign them their **Direct Reports**.\n\n## What changes\n\nThey immediately gain access to the **Approvals** page for their direct reports and can view team-scoped reports. Their own time tracking and expense workflow stays the same.\n\n💡 Pro tip: Brief new managers on the approvals workflow before promoting them — a 5-minute walkthrough prevents confusion.", category: "Management", keywords: "promote team member manager role upgrade team-member permission change elevate admin", pages: ["/team"] },
  { id: "payout-stripe-1", title: "🤝 Stripe Connect for team payouts", body: "Stripe Connect turns payouts from a manual process into a one-click operation — fast, tracked, and reconciled.\n\n## How it works\n\nTeam members connect their bank account through Stripe's secure onboarding. Once set up, you can send payouts from the **Payouts** page with a single click.\n\n## Settlement\n\nFunds arrive in the team member's bank account within 1-2 business days. The payment records and GL entry post automatically.\n\n💡 Pro tip: Have your team members complete Stripe onboarding during their first week — it eliminates payout friction from day one.", category: "Payments", keywords: "stripe connect payout team member transfer bank account direct deposit partner onboarding 1099 fast payment", pages: ["/payouts"] },
  { id: "pay-4", title: "💸 Setting up team member Stripe Connect accounts", body: "Each team member needs to connect their own Stripe account — here's how to guide them through it.\n\n## Sending the invite\n\nFrom the team member's profile, click **Send Stripe Connect Invite**. They'll receive an email with a secure link to complete onboarding.\n\n## What they provide\n\nStripe asks for their legal name, date of birth, SSN (last 4), and bank account details. This is handled entirely by Stripe — CherryWorks never sees sensitive banking data.\n\n## Verification\n\nOnce verified, a green **Connected** badge appears on their profile, and you can start sending payouts.\n\n💡 Pro tip: Send the Stripe invite the same day you add the team member — most people complete it within 10 minutes.", category: "Payments", keywords: "stripe connect team member account setup bank link tax identity verify transfer payment", pages: ["/payouts"] },
  { id: "pay-5", title: "🏦 Accepting ACH bank transfer payments", body: "ACH payments mean lower fees for you and a simple experience for your clients.\\n\\n## Enabling ACH\\n\\nEnable **ACH Bank Transfer** in **Settings** → **Billing & Invoicing** through your connected Stripe account. The ACH option appears alongside card payment on client invoices.\\n\\n## Client experience\\n\\nClients enter their routing and account numbers. The payment takes 3-5 business days to settle and records automatically against the invoice.\\n\\n💡 Pro tip: Highlight ACH as the preferred method for invoices over $1,000 — the fee savings are significant on larger amounts.", category: "Payments", keywords: "ACH bank transfer payment stripe checkout processing fee settlement business days 0.8% cap invoice payment method", pages: ["/payments","/invoices"] },
  { id: "team-class-1", title: "👥 W-2 vs 1099 vs C2C worker classifications", body: "Each worker type has different tax, payout, and GL implications — getting this right from day one saves major headaches.\n\n## W-2 Employees\n\nYou withhold taxes and handle payroll through your provider. CherryWorks doesn't generate auto-payouts for W-2s. GL impact flows via payroll integration.\n\n## 1099 Independents\n\nNo tax withholding. Auto-payouts generate when invoices are sent. Pay via check, ACH, or Stripe Connect. GL posts Accrued 1099 Liability → Cash.\n\n## C2C (Corp-to-Corp)\n\nThe team member operates as their own business entity. Same payout mechanics as 1099 — no 1099-NEC issued. GL posts Accrued C2C Liability → Cash.\n\n💡 Pro tip: Consult your CPA before classifying team members — one misclassification can trigger IRS penalties.", category: "Team", keywords: "W-2 employee 1099 team member C2C corp-to-corp worker type classification tax payout GL", pages: ["/team"] },
  { id: "team-names-1", title: "📋 Setting up first and last names", body: "Clean name data powers professional invoices, estimates, and client-facing documents.\n\n## Setting names\n\nWhen inviting a team member, enter their **First Name** and **Last Name** separately. These populate invoice headers, estimate signatures, and the client portal.\n\n## Updating\n\nEdit names anytime from the team member's profile page. Changes reflect across all future documents immediately.\n\n💡 Pro tip: Double-check name spelling before the first invoice goes out — typos on client-facing documents look unprofessional.", category: "Team", keywords: "first name last name display legal name team member invoice payroll 1099 tax form professional", pages: ["/team"] },
  { id: "team-payroll-1", title: "🔗 Connecting to payroll via Zapier webhooks", body: "Bridge CherryWorks to your payroll system without custom code — Zapier makes it plug-and-play.\\n\\n## Setting up the webhook\\n\\nIn **API & Integrations**, add a webhook URL for your Zapier trigger. Choose which events fire the webhook: **Timesheet Approved**, **Payout Completed**, or **Team Member Added**.\\n\\n## Common workflows\\n\\nSync approved timesheets to Gusto or ADP, push completed payouts to QuickBooks, or trigger Slack alerts when payroll-related events fire.\\n\\n💡 Pro tip: Start with the **Timesheet Approved** webhook — it's the most common bridge between CherryWorks and payroll.", category: "Team", keywords: "zapier webhook payroll integration payout automation ADP Gusto Rippling employee team member first last name sync", pages: ["/team","/payouts"] },
  { id: "imp-wizard-1", title: "🔄 Multi-platform import wizard overview", body: "The import wizard walks you through migrating data from any supported platform — step by step with safety nets.\n\n## The flow\n\nSelect a platform → choose a data type → upload your file → auto-map columns → dry-run preview → execute import → review results.\n\n## Safety nets\n\nEvery import includes a dry-run preview and a post-import rollback option. You can undo the entire import with a single click if anything looks wrong.\n\n💡 Pro tip: Import data types in this order — Clients, Services, Projects, Time Entries, Invoices, Expenses — to avoid broken references.", category: "Import", keywords: "import wizard migration platform QuickBooks Xero Wave FreshBooks upload file field mapping preview confirm", pages: ["/import"] },
  { id: "imp-platforms-1", title: "📊 Supported import platforms", body: "CherryWorks supports direct imports from 8 platforms — each with optimized column mappings.\n\n## The platforms\n\n**FreshBooks**, **QuickBooks**, **Harvest**, **Xero**, **Wave**, **BigTime**, **Scoro**, and **Paymo** — each has a branded import card with its real logo and colors.\n\n## What you can import\n\nUp to 8 data types per platform: Clients, Vendors, Services, Time Entries, Invoices, Expenses, GL Opening Balances (accounting platforms), and Projects (PSA platforms).\n\n💡 Pro tip: Check your old platform's export options first — some limit what you can export on free or lower-tier plans.", category: "Import", keywords: "import platform QuickBooks Xero Wave FreshBooks Zoho BigTime Scoro Paymo CSV export integration supported", pages: ["/import"] },
  { id: "imp-3-gl", title: "💰 Importing GL opening balances", body: "Bring your historical account balances into CherryWorks so your GL starts with accurate numbers.\n\n## What gets imported\n\nAccount numbers, names, and opening debit/credit balances from your previous accounting system. These become the starting point for your CherryWorks GL.\n\n## After import\n\nRun the **Trial Balance** to verify everything is balanced. If the import created an imbalance, add a manual journal entry to correct it.\n\n💡 Pro tip: Import opening balances before recording any new transactions — it keeps your GL chronologically clean.", category: "Import", keywords: "import GL opening balance chart accounts journal entry trial balance fiscal year migration initialization asset liability", pages: ["/import"] },
  { id: "imp-4-proj", title: "📁 Importing projects and team assignments", body: "Migrate your project structure so your team can start logging time against existing projects immediately.\n\n## What gets imported\n\nProject names, client assignments, budget types, budget amounts, and team member assignments (if available in your export).\n\n## Post-import\n\nReview each project to confirm settings are correct. Client relationships and budget types may need manual adjustment depending on your source platform's format.\n\n💡 Pro tip: Import projects before time entries — entries need projects to attach to, not the other way around.", category: "Import", keywords: "import project team assignment bill rate cost rate profitability budget hours migration client manager", pages: ["/import"] },
  { id: "api-1", title: "🔓 Enabling the REST API", body: "Open up CherryWorks to your custom integrations — the REST API gives you programmatic access to your data.\\n\\n## Enabling\\n\\nGo to **API & Integrations** in the sidebar and toggle **Enable REST API** on. This makes all API endpoints accessible with a valid API key.\\n\\n## What's available\\n\\nFull CRUD access to clients, invoices, time entries, expenses, payments, projects, team members, and GL data. All endpoints return JSON and follow RESTful conventions.\\n\\n💡 Pro tip: Enable the API only when you need it — if you're not using integrations, keeping it off reduces your attack surface.", category: "API & Webhooks", keywords: "REST API enable access key authentication professional plan rate limits endpoints integration", pages: ["/api-integrations"] },
  { id: "api-2", title: "🔑 Creating and managing API keys", body: "API keys authenticate your integrations — treat them like passwords and rotate them regularly.\\n\\n## Creating a key\\n\\nIn **API & Integrations**, click **Create API Key**. Give it a descriptive name (e.g., \\\"Zapier Integration\\\" or \\\"BI Dashboard\\\") so you know what it's for.\\n\\n## Security\\n\\nKeys are shown once at creation — copy and store them securely. You can revoke any key at any time without affecting other keys.\\n\\n💡 Pro tip: Create separate API keys for each integration — if one gets compromised, you can revoke it without breaking everything else.", category: "API & Webhooks", keywords: "API key generate create revoke rotate authentication X-API-Key header integration Zapier security", pages: ["/api-integrations"] },
  { id: "api-3", title: "🪝 Setting up webhooks", body: "Webhooks push real-time events to your systems — no polling required.\\n\\n## Configuring\\n\\nIn **API & Integrations**, click **Add Webhook Endpoint**. Enter your endpoint URL and select which events to listen for: invoice sent, payment received, timesheet approved, expense approved, payout completed, and more.\\n\\n## Payload\\n\\nEach webhook sends a JSON payload with the event type, timestamp, and the full record that triggered it. Your endpoint should respond with a 200 status.\\n\\n💡 Pro tip: Use a webhook testing tool like webhook.site during setup — it lets you inspect payloads before wiring up production code.", category: "API & Webhooks", keywords: "webhook event listener invoice payment expense approval HTTP POST endpoint Slack Zapier automation real-time notification", pages: ["/api-integrations"] },
  { id: "api-4", title: "⏱️ API rate limits and best practices", body: "CherryWorks API has rate limits to keep things fair — here's how to stay within them.\\n\\n## Rate limits\\n\\nThe API allows **1000 requests per minute** per API key. Exceeding the limit returns a 429 status with a Retry-After header.\\n\\n## Best practices\\n\\nBatch operations where possible, cache frequently-accessed data, use webhooks instead of polling for real-time updates, and implement exponential backoff for retries.\\n\\n💡 Pro tip: Use webhooks for real-time data instead of polling — it's faster, uses zero rate-limit budget, and reduces server load.", category: "API & Webhooks", keywords: "rate limit quota 1000 per minute requests per second HTTP 429 retry backoff batch cache webhook pagination", pages: ["/api-integrations"] },
  { id: "billing-1", title: "Manage your subscription plan", body: "Upgrade, downgrade, or switch plans anytime — changes take effect at your next billing cycle.\\n\\n## Viewing your plan\\n\\nGo to **Settings** → **Subscription** to see your current plan, usage, and limits. The page shows how many team members, clients, and projects you're using against your plan's caps.\\n\\n## Changing plans\\n\\nClick **Manage Subscription** to compare available tiers. Upgrades take effect immediately; downgrades apply at the end of your current billing period.\\n\\n💡 Pro tip: Check your usage monthly — if you're consistently near plan limits, upgrading proactively avoids disruptions.", category: "Billing", keywords: "subscription plan cancel downgrade upgrade billing payment change pricing manage account", pages: ["/settings"] },
  { id: "billing-2", title: "Update your payment method", body: "Keep your payment method current to avoid service interruptions.\\n\\n## Updating\\n\\nIn **Settings** → **Subscription**, click **Add payment method** or **Manage Subscription** to update your card details — the change applies to your next charge.\\n\\n## Supported methods\\n\\nCredit cards and debit cards via Stripe. Your card information is stored securely by Stripe — CherryWorks never sees your full card number.\\n\\n💡 Pro tip: Set a calendar reminder for when your card expires — a failed payment can temporarily suspend your account.", category: "Billing", keywords: "payment method card credit update change billing stripe declined retry charge", pages: ["/settings"] },
  { id: "billing-3", title: "View billing history and receipts", body: "Access every invoice CherryWorks has charged you — downloadable receipts for your records.\\n\\n## Viewing history\\n\\nIn **Settings** → **Subscription**, click **Manage Subscription** to see every charge, its date, amount, and status through your Stripe billing portal.\\n\\n## Downloading receipts\\n\\nClick any charge to download a PDF receipt for your accounting records or expense reports.\\n\\n💡 Pro tip: Download all receipts at tax time — your CherryWorks subscription is a deductible business expense.", category: "Billing", keywords: "billing history receipt invoice download PDF charge payment record tax expense", pages: ["/settings"] },
  { id: "billing-4", title: "Understanding plan limits and features", body: "Each plan tier unlocks different capabilities and capacity — here's what to know.\\n\\n## Key differences\\n\\nPlans differ on **team member count**, **client count**, **project count**, feature access (API, imports, banking, advanced reports), and support level.\\n\\n## Checking your limits\\n\\nIn **Settings** → **Subscription**, the usage dashboard shows your current consumption against each limit with clear progress bars.\\n\\n## Hitting a limit\\n\\nWhen you reach a limit, CherryWorks prompts you to upgrade. Existing data is never deleted — you just can't add more until you upgrade.\\n\\nMarketing OS is included on **Business** and **Enterprise** plans — see **What is Marketing OS** for what unlocks.\\n\\n💡 Pro tip: Enterprise plans have unlimited everything — if you're growing fast, it's worth upgrading early to avoid constant limit bumps.", category: "Billing", keywords: "plan starter professional business enterprise features limits pricing tier upgrade per user unlimited", pages: ["/settings","/pricing"] },
  { id: "sup-1", title: "☎️ Escalating to support", body: "Stuck on something the Knowledge Base can't solve? Here's how to get human help fast.\n\n## Contact options\n\nEmail **support@cherrystconsulting.com** with your issue description and any relevant screenshots. Include your org name and the page where you encountered the problem.\n\n## Response times\n\nEnterprise plans get priority support with faster response times. All plans receive a response within one business day.\n\n💡 Pro tip: Include a screenshot and the URL of the page where you hit the issue — it cuts resolution time in half.", category: "Support", keywords: "support contact escalate issue help panel form email urgent phone assistance response time", pages: ["/"] },
  { id: "guide-1", title: "📘 Implementation Guide Overview", body: "Your roadmap from signup to fully operational — six phases that take a typical firm from zero to billing in under a week.\n\n## The six phases\n\nFoundation Setup → Service & Rate Configuration → Team Onboarding → Client & Project Setup → Data Migration → Go Live & Verify.\n\n## How to use it\n\nWork through each phase in order. Each phase has clear deliverables and a completion checklist. Skip phases that don't apply to your firm.\n\n💡 Pro tip: Block 2-3 hours on day one for Phases 1-3 — most firms can complete them in a single sitting.", category: "Getting Started", keywords: "implementation guide overview setup phases foundation services team clients migration go live 15 minutes accordion steps checklist", pages: ["/getting-started"] },
  { id: "guide-2", title: "🏗️ Phase 1: Foundation Setup", body: "Get the basics locked in — your firm identity, currency, and core settings.\\n\\n## What to set up\\n\\nCompany name, logo, address, **Base Currency**, **Invoice Prefix**, **Estimate Prefix**, and email/SMTP configuration. These are found in **Settings** across the **Organization**, **Billing & Invoicing**, and **Accounting & Email** tabs.\\n\\n## Why it matters\\n\\nSkipping foundation setup means your first invoice goes out with placeholder branding — not the impression you want to make.\\n\\n💡 Pro tip: Upload your logo and set your address before anything else — it takes 2 minutes and every document looks professional from day one.", category: "Getting Started", keywords: "foundation setup firm profile billing defaults SMTP email chart of accounts GL currency payment terms invoice prefix tax rate logo branding phase 1", pages: ["/getting-started"] },
  { id: "guide-3", title: "👥 Phase 3: Team Onboarding", body: "Get your team into CherryWorks so they can start tracking time and logging expenses.\n\n## What to do\n\nInvite each team member with their email, **Role** (Admin, Manager, Team Member), **Worker Type** (W-2, 1099, C2C), and their **Bill Rate** and **Pay Rate**. They'll receive an email to set their password.\n\n## Post-invite\n\nHave each person log in, complete their profile (name, avatar), and log a test time entry. This confirms everything is working before real work begins.\n\n💡 Pro tip: Do a 15-minute team walkthrough on day one — it prevents a week of \"how do I...\" questions.", category: "Getting Started", keywords: "team onboarding add members invite W-2 1099 C2C worker type classification role team-member manager admin bill rate cost rate profitability phase 3", pages: ["/getting-started"] },
  { id: "guide-4", title: "📦 Phase 5: Data Migration", body: "Bring your historical data into CherryWorks so you're not starting from scratch.\n\n## What to migrate\n\nClients, services, projects, time entries, invoices, expenses, and GL opening balances (if applicable). Use the **Import Wizard** for each data type.\n\n## Order matters\n\nImport in this sequence: Clients → Services → Projects → Time Entries → Invoices → Expenses → GL Balances. This ensures all references resolve correctly.\n\n💡 Pro tip: Run a dry-run for each import type — catching mapping errors before commit saves hours of cleanup.", category: "Getting Started", keywords: "data migration import FreshBooks QuickBooks Harvest Xero Wave CSV fresh start skip historical clients invoices time entries GL validate dry run phase 5", pages: ["/getting-started"] },
  { id: "guide-5", title: "🚀 Phase 6: Go Live & Verify", body: "You've set up everything — now verify it all works before going live with real clients.\n\n## Verification checklist\n\nCreate a test invoice and send it to yourself. Record a test payment. Submit a timesheet. Log an expense. Run the Trial Balance. If everything checks out, you're ready.\n\n## Going live\n\nStart sending real invoices, tracking real time, and inviting clients to the portal. Keep the Getting Started page bookmarked for the first week.\n\n💡 Pro tip: Go live on a Monday — you'll have the full week to catch any issues before the weekend.", category: "Getting Started", keywords: "go live verify smoke test time entry invoice dashboard setup complete production ready phase 6 revenue hours clients check confirm", pages: ["/getting-started"] },
  { id: "cp-1", title: "🔐 Change your password", body: "Update your CherryWorks password anytime from the dedicated change-password screen.\\n\\n## Getting there\\n\\nOpen your profile menu (top-right avatar) and click **Change Password**, or navigate to **/change-password** directly.\\n\\n## The form\\n\\nEnter your **Current Password**, then a **New Password** (at least 8 characters), and **Confirm Password**. Click **Set Password & Continue** — you'll be bounced back to the dashboard with the new password active.\\n\\n## First-time login\\n\\nIf an admin created your account with a temporary password, you'll land here automatically — the Current Password field is skipped so you can set your real password right away.\\n\\n💡 Pro tip: Use a password manager — every CherryWorks password is unique to your org, so mixing up credentials is a fast way to get locked out.", category: "Account", keywords: "change password reset update security account credentials temporary login 8 characters minimum first time admin created", pages: ["/change-password"] },
  { id: "ob-1", title: "🚀 Completing onboarding", body: "Your first login walks you through a guided setup — profile, business, payment, address, then review — so CherryWorks can pay you correctly and send you tax docs.\\n\\n## The steps\\n\\n**Profile** (name, phone) → **Business** (pay-to name, EIN, W-9, agreement) → **Payment** (ACH or Zelle) → **Address** (for 1099 or W-2) → **Review**. W-2 employees skip Business and Payment since payroll handles those.\\n\\n## What you need on hand\\n\\nYour EIN (or SSN if sole prop), bank routing and account numbers for ACH, or a Zelle email/phone. Address must be the one on your tax documents.\\n\\n## Finishing\\n\\nClick **Go to Dashboard** on the Review step — your account is activated and you're dropped into the Getting Started guide.\\n\\n💡 Pro tip: Have your W-9 signed and your banking info copy-ready before you start — the full flow takes about 3 minutes if you don't have to hunt for numbers.", category: "Getting Started", keywords: "onboarding new user first time setup profile business payment address review W-9 EIN ACH Zelle 1099 W-2 worker type bank routing account number finish dashboard", pages: ["/onboarding"] },
  { id: "notif-1", title: "🔔 Reviewing your notifications", body: "The Notifications page is your inbox for everything CherryWorks wants you to know — timesheet approvals, payments, invoice views, and system alerts.\\n\\n## Opening it\\n\\nClick the **bell icon** in the top navigation or go to **/notifications**. Unread notifications show a badge count (e.g., \\\"5 unread\\\").\\n\\n## Filtering\\n\\nUse **Filter by type** to narrow by notification category (timesheet, payment, invoice, approval, etc.). The filter persists while you're on the page.\\n\\n## Managing\\n\\nClick any notification to jump to its source record. Click **Mark all read** to clear the unread badge. Each row has a trash icon to delete.\\n\\n💡 Pro tip: Check Notifications first thing each morning — invoice views and payment confirmations land here in real time, so you'll see what needs follow-up before you open email.", category: "Account", keywords: "notifications bell inbox alerts unread mark all read filter type delete timesheet payment invoice approval system message realtime updates badge count", pages: ["/notifications"] },
  { id: "act-1", title: "🕵️ Activity feed audit trail", body: "The Activity feed is a read-only log of every meaningful action across your org — who did what, to which record, and when.\\n\\n## Access\\n\\nManagers and Admins can open **Activity** from the sidebar. Team Members don't see this page.\\n\\n## Filters\\n\\nFour filter dropdowns narrow the view: **All Users** (actor), **All Types** (entity type — invoice, expense, client, etc.), **All Actions** (created, updated, deleted, sent, approved, etc.), and **All Time** (date range — today, week, month, custom).\\n\\n## Use it to\\n\\nInvestigate who changed an invoice before it was sent, confirm a payment was recorded by the right person, or spot-check team activity during an audit.\\n\\n💡 Pro tip: Set the Actor filter to a specific user plus Action = \\\"deleted\\\" to quickly see what someone removed — the activity log is append-only, so deleted records still have a trail.", category: "Admin", keywords: "activity feed audit log history trail who changed when created updated deleted sent approved filter actor entity type action date range manager admin", pages: ["/activity"] },
  { id: "adm-1", title: "🗄️ Data Console (Admin)", body: "The Data Console gives admins a raw CRUD view into every entity in the system — clients, projects, invoices, time entries, expenses, payments, GL records, and more.\\n\\n## Getting there\\n\\nNavigate to **/admin/data** or click **Data Console** in the admin sidebar. You'll see a grid of entity cards.\\n\\n## Browsing\\n\\nClick any entity card to see the full list with search and pagination (50 per page). Click a row to inspect or edit that record in detail.\\n\\n## View Only vs editable\\n\\nSome entities (audit records, system tables) are tagged **View Only** — you can read but not modify. Editable entities let you update any field directly, bypassing the normal UI.\\n\\n## Caution\\n\\nThe Data Console is a power tool — changes here skip business-rule validation. Use it for data cleanup, migrations, and emergency fixes, not routine edits.\\n\\n💡 Pro tip: Before editing a record, use the Activity feed to see its history — you'll avoid overwriting a change someone else just made.", category: "Admin", keywords: "admin data console CRUD raw edit entity clients projects invoices time entries expenses payments GL view only search pagination power tool cleanup migration", pages: ["/admin/data"] },
  { id: "api-intro", title: "🔌 API & Integrations overview", body: "The API & Integrations page is the control center for extending CherryWorks — REST API keys, webhook endpoints, and inline API documentation all live here.\\n\\n## Sections\\n\\n**API Keys** — create, rotate, and revoke keys for integrations (Zapier, BI tools, custom apps). **Webhooks** — push real-time events (invoice sent, payment received, timesheet approved) to your endpoints. **API Documentation** — authentication format, available endpoints, example requests, and webhook event reference.\\n\\n## Who can access it\\n\\nAdmin role only. Managers and Team Members don't see this page.\\n\\n💡 Pro tip: Start with the **API Documentation** section — the example requests can be copied straight into Postman or curl to confirm your API key works before you wire up real code.", category: "API & Webhooks", keywords: "API integrations overview REST keys webhooks documentation admin Zapier BI custom integration endpoint authentication example requests", pages: ["/api-integrations"] },
  { id: "close-1", title: "🔒 Close periods (lock accounting data)", body: "Close Periods let you lock a date range so time entries, invoices, expenses, and GL records in that window can't be changed — critical for audit and month-end close.\\n\\n## Creating a close period\\n\\nGo to **Close Periods**, click **New Close Period**. Enter the period start and end dates, optional notes, and confirm — the period is locked immediately.\\n\\n## Viewing and managing\\n\\nThe page lists every period with status (OPEN or CLOSED), close timestamp, and notes. Each row has actions to **Close** (lock) or **Reopen** (unlock if you have admin permission).\\n\\n## What locking does\\n\\nAttempts to edit or create records dated inside a closed period are blocked at the API layer. You'll see a \\\"Period is closed\\\" error anywhere you try.\\n\\n💡 Pro tip: Close the prior month on the 10th of each month — gives your team time to finish timesheet submissions while still protecting prior-month books from retroactive edits.", category: "Admin", keywords: "close period lock accounting month end audit protection time entries invoices expenses GL period start end status closed open reopen admin", pages: ["/close-periods"] },
  { id: "mkt-1", title: "📣 What is Marketing OS", body: "Marketing OS is the email-marketing add-on for CherryWorks — campaigns, sequences, contacts, tags, and deliverability tooling under one roof.\\n\\n## Who it's for\\n\\nFirms and agencies that want to send broadcast campaigns, drip sequences, and re-engagement emails to prospects and clients without leaving CherryWorks.\\n\\n## What you get\\n\\nA dedicated **Marketing** section with campaigns, contacts, segments, tags, sequences, suppression list, and an activity firehose for diagnosing every send.\\n\\n## Plan availability\\n\\nMarketing OS is included on **Business** and **Enterprise** plans. Starter, Trial, and Professional users can preview the help docs but campaign sending is gated.\\n\\n💡 Pro tip: Read the four Foundations articles in order — set up your sender identity, take the tour, and ship a 5-minute first campaign before touching contacts at scale.", category: "Marketing", keywords: "marketing os overview introduction what is add-on business enterprise plan campaigns sequences contacts deliverability email", pages: ["/marketing"] },
  { id: "mkt-2", title: "✉️ Set up your sender identity", body: "Before any campaign goes out, configure who emails come from and verify your domain so inboxes trust you.\\n\\n## Where to set it\\n\\n**Marketing** → **Settings** → **Sender Identity**. Enter the **From Name**, **From Email**, **Reply-To**, and the **Sending Domain** you want to authenticate.\\n\\n## Verifying the domain\\n\\nAdd the SPF and DKIM records shown in the panel to your DNS provider, then click **Verify**. The badge flips to green within a few minutes once propagation completes.\\n\\n## What breaks without it\\n\\nUnverified domains land in spam, get rate-limited, or are rejected outright by Gmail and Outlook. Verify before importing contacts.\\n\\n💡 Pro tip: Use a real human address as the Reply-To (e.g. hello@yourfirm.com) — replies route back as conversations, which lifts engagement and reply-rate dramatically.", category: "Marketing", keywords: "sender identity from name email reply-to domain SPF DKIM verify authentication setup configuration marketing", pages: ["/marketing"] },
  { id: "mkt-3", title: "🧭 Tour of the Marketing section", body: "The Marketing section in the sidebar is your home base for everything send-related.\\n\\n## The pages\\n\\n**Campaigns** for one-off broadcasts, **Sequences** for multi-step drips, **Contacts** for the recipient database, **Segments** for dynamic audiences, **Tags** for static groupings, **Suppression** for bounces and unsubscribes, and **Activity** for the per-send firehose.\\n\\n## Who can see it\\n\\nAdmins always see Marketing on Business+ plans. Managers and Team Members see it only if your firm grants their role access in **Settings** → **Roles**.\\n\\n## Starter and Professional users\\n\\nThe section appears with a lock badge so you can preview titles and decide whether to upgrade — bodies stay gated until you switch to Business.\\n\\n💡 Pro tip: Pin **Activity** in your browser tab during your first week — it's the fastest way to spot a misconfigured campaign before it damages your sender reputation.", category: "Marketing", keywords: "marketing tour overview navigation campaigns sequences contacts segments tags suppression activity sidebar pages roles admin manager", pages: ["/marketing"] },
  { id: "mkt-4", title: "🚀 Send your first campaign in 5 minutes", body: "Five steps from blank slate to a campaign sitting in your test inbox.\\n\\n## The flow\\n\\nGo to **Marketing** → **Campaigns** → **New Campaign**. Pick **One-off**, name it, and click **Continue**.\\n\\n## Pick the audience\\n\\nChoose a tag, segment, or list. For your first send, target a tag containing only your own email — you'll preview deliverability without spamming anyone.\\n\\n## Write and review\\n\\nSet a **Subject**, drop in copy in the editor, and click **Send Test** to verify formatting in your inbox. Then **Send Now** or **Schedule**.\\n\\n## Confirm\\n\\nThe campaign moves to **Sent** with open and click counters that begin populating within a few minutes.\\n\\n💡 Pro tip: Always send a test to yourself before any real campaign — even a one-character typo in the subject line costs you opens you can never get back.", category: "Marketing", keywords: "first campaign quickstart 5 minutes new campaign one-off audience subject send test send now schedule confirm", pages: ["/marketing","/marketing/campaigns"] },
  { id: "mkt-5", title: "📨 Create a one-off campaign", body: "One-off campaigns are single-send broadcasts — newsletters, announcements, promos.\\n\\n## Starting one\\n\\n**Marketing** → **Campaigns** → **New Campaign** → **One-off**. Name it for internal reference (recipients never see this).\\n\\n## The fields\\n\\n**Subject** (the only field that matters for opens), **Preheader** (preview text after the subject in inboxes), **From Name** and **From Email** (defaults pull from your Sender Identity), and the **Body** in the rich-text or HTML editor.\\n\\n## Saving as draft\\n\\nEvery edit autosaves. Drafts live under **Campaigns** → **Drafts** and can be edited or duplicated indefinitely.\\n\\n💡 Pro tip: Spend 80% of your effort on the subject line and 20% on the body — open rate is the gate everything else flows through.", category: "Marketing", keywords: "one-off campaign single send broadcast newsletter announcement subject preheader body draft autosave create new", pages: ["/marketing/campaigns"] },
  { id: "mkt-6", title: "🕒 Schedule vs send now", body: "You can fire a campaign immediately or queue it for a future time.\\n\\n## Send Now\\n\\nClick **Send Now** on the review screen. The campaign moves to a **Sending** state and the worker starts streaming messages within seconds. Large lists trickle out over a few minutes to respect rate limits.\\n\\n## Schedule\\n\\nClick **Schedule** instead and pick a date and time in your org's timezone. Scheduled campaigns sit in **Scheduled** and dispatch automatically at the chosen moment.\\n\\n## Cancelling\\n\\nA scheduled campaign can be cancelled or rescheduled any time before its dispatch time. A campaign that's already in Sending can't be paused — only suppressed by adding contacts to the Suppression list.\\n\\n💡 Pro tip: Tuesday or Wednesday between 9am and 11am in your audience's local timezone consistently wins on open rate. Schedule rather than improvising at midnight.", category: "Marketing", keywords: "schedule send now scheduled sending dispatch timezone cancel reschedule campaign queue worker", pages: ["/marketing/campaigns"] },
  { id: "mkt-7", title: "🎯 Choose your audience (segment, tag, or list)", body: "Every campaign needs a recipient pool. Three surfaces let you pick.\\n\\n## Tags\\n\\n**Static** labels you attach manually to contacts (e.g. q4-prospects). Use tags for hand-curated, one-time audiences.\\n\\n## Segments\\n\\n**Dynamic** rule-based queries (e.g. opened any email in last 30 days AND has tag prospect). Membership recalculates at send time, so a segment for engaged contacts stays accurate without maintenance.\\n\\n## Lists\\n\\nUploaded CSV groups, useful when an external source (an event registration, a partner list) hands you a one-time batch.\\n\\n## Picking one\\n\\nThe **Choose Audience** step shows the count for each option. If a segment shows 0 recipients, your filter is too narrow.\\n\\n💡 Pro tip: When in doubt between a tag and a segment, ask whether this audience changes over time — yes means segment, no means tag.", category: "Marketing", keywords: "audience segment tag list choose recipients pool dynamic static rule query CSV upload campaign target", pages: ["/marketing/campaigns"] },
  { id: "mkt-8", title: "📝 Edit or duplicate a draft", body: "Iterating on a campaign is normal — most go through three or four edits before they ship.\\n\\n## Editing\\n\\nOpen any draft from **Campaigns** → **Drafts** and the editor reopens at the last step you were on. Edits autosave; there's no separate save button.\\n\\n## Duplicating\\n\\nFrom **Sent** or **Drafts**, click the kebab menu and choose **Duplicate**. A copy lands in Drafts with (Copy) appended to the name. Subject, body, and audience are copied; send timestamps are not.\\n\\n## Reverting\\n\\nThere's no version history yet — if you overwrite content by mistake, the duplicate workflow is your safety net.\\n\\n💡 Pro tip: Before any major rewrite, click Duplicate first. The 5-second copy is cheap insurance against an accidental save you can't undo.", category: "Marketing", keywords: "edit duplicate draft campaign autosave kebab copy revert version history rewrite", pages: ["/marketing/campaigns"] },
  { id: "mkt-9", title: "📊 Review send results", body: "After a campaign sends, the results page tells you whether it landed.\\n\\n## The metrics\\n\\n**Delivered** (passed inbox filtering), **Opens** (unique recipients who loaded the tracking pixel), **Clicks** (unique recipients who hit a tracked link), **Replies** (inbound responses), **Bounces** (hard + soft), and **Unsubscribes**.\\n\\n## Per-recipient view\\n\\nClick **Recipients** to see exactly who opened, clicked, bounced, or unsubscribed. Useful for following up on warm leads or pruning bad addresses.\\n\\n## Healthy benchmarks\\n\\nFor B2B sends, 25–35% open rate, 2–5% click rate, and under 2% bounce rate are healthy. Anything outside that warrants investigation.\\n\\n💡 Pro tip: Re-target everyone in the **Clicks** bucket with a follow-up sequence one week later — they raised their hand and conversion lifts substantially.", category: "Marketing", keywords: "send results metrics opens clicks replies bounces unsubscribes delivered recipients benchmarks campaign analytics", pages: ["/marketing/campaigns"] },
  { id: "mkt-10", title: "👥 Marketing contacts overview", body: "Marketing contacts are the people you can email from campaigns and sequences — distinct from your accounting Clients table.\\n\\n## Where they live\\n\\n**Marketing** → **Contacts** lists every recipient with email, name, source, tags, and engagement summary.\\n\\n## How they get there\\n\\nManually added one-by-one, imported from CSV, synced from a connected list, or auto-created when someone replies to a campaign.\\n\\n## Contacts vs Clients\\n\\nA marketing **Contact** is a prospect or lead. An accounting **Client** is someone you invoice. The same person can exist as both — convert a Contact to a Client via the kebab menu when they sign on.\\n\\n💡 Pro tip: Tag every contact with their source (source-event, source-referral, source-website) at create time — campaign segmentation by source is the single most useful slice.", category: "Marketing", keywords: "marketing contacts overview database recipients clients prospects leads source tags engagement convert", pages: ["/marketing/contacts"] },
  { id: "mkt-11", title: "📥 Import marketing contacts", body: "Bring contacts in from CSV, your CRM, or a partner export.\\n\\n## Starting the import\\n\\n**Marketing** → **Contacts** → **Import**. Upload a CSV and the wizard maps your columns to **Email**, **First Name**, **Last Name**, **Company**, and any custom fields.\\n\\n## Tagging on import\\n\\nAdd a tag during the import (e.g. imported-2026-q1) so you can find or roll back the batch later. Strongly recommended.\\n\\n## Duplicates\\n\\nThe import deduplicates by email — existing contacts get the new tag and field updates without being recreated.\\n\\n## Marketing import vs accounting import\\n\\nThis is separate from the **Import** wizard for accounting data (clients, invoices, GL). Marketing contacts never touch your books.\\n\\n💡 Pro tip: Run a 10-row sample import first. Catching a column-mapping mistake on 10 rows is trivial; catching it on 50,000 means a manual cleanup or a full delete-and-redo.", category: "Marketing", keywords: "import marketing contacts CSV upload columns mapping email name company tag deduplicate sample wizard", pages: ["/marketing/contacts","/marketing/contacts/import"] },
  { id: "mkt-12", title: "🏢 Companies in Marketing", body: "Companies group contacts by employer — useful for account-based outreach.\\n\\n## Where they live\\n\\n**Marketing** → **Companies** lists each company with contact count, last-touch date, and aggregated engagement.\\n\\n## How they're created\\n\\nAuto-derived from the **Company** field on contacts at import time, or added manually. Editing a company name updates every linked contact.\\n\\n## Using companies\\n\\nSegment by company size, industry, or last-touch. Useful for prioritising sequence enrolment to companies with multiple engaged contacts.\\n\\n💡 Pro tip: Add the company **domain** field on import (not just the name) — segmenting by domain is more reliable than by name when the same company appears as Acme, Acme Inc, and Acme, Inc.", category: "Marketing", keywords: "companies marketing account-based outreach contact count engagement domain segment industry size", pages: ["/marketing/companies"] },
  { id: "mkt-13", title: "🏷️ Tag basics & tagging strategy", body: "Tags are static, manually-applied labels on contacts.\\n\\n## Creating tags\\n\\nAny new tag string applied during import or on a contact's profile auto-creates the tag. View the full list under **Marketing** → **Tags**.\\n\\n## Use tags for\\n\\nManual lists, source attribution, campaign exclusions, and one-time audiences — anything where membership doesn't change automatically.\\n\\n## Tag vs segment\\n\\nIf the audience changes based on behaviour or fields (e.g. opened in last 30 days), use a **segment** instead. If you're hand-picking a fixed group, use a **tag**.\\n\\n## Naming convention\\n\\nUse category-value format (source-event, topic-pricing, lifecycle-prospect). It scales — a flat list of 200 random labels becomes unmanageable fast.\\n\\n💡 Pro tip: Reserve a do-not-email tag for compliance opt-outs that aren't full unsubscribes (for example, a client requesting a 60-day pause). Add it to every campaign exclusion.", category: "Marketing", keywords: "tags tagging strategy static label contacts naming convention exclusion compliance do-not-email", pages: ["/marketing/tags"] },
  { id: "mkt-14", title: "🧪 Dynamic vs static segments", body: "Segments answer who matches these rules right now — and the answer changes as your contacts change.\\n\\n## Dynamic segments\\n\\nThe default. Build a query in the segment editor (e.g. tag = prospect AND opened any email in last 30 days). The contact list recalculates at every send.\\n\\n## Static segments\\n\\nA dynamic segment can be **frozen** — converted to a fixed list of contact IDs. Useful when you want everyone who matched on Black Friday preserved even after their tags change.\\n\\n## Choosing\\n\\nDynamic for most marketing — they self-maintain. Static when an audience is tied to a moment in time.\\n\\n## Performance\\n\\nDynamic segments resolve in milliseconds for under 100k contacts. Beyond that, freezing on a schedule keeps send-prep snappy.\\n\\n💡 Pro tip: Build segments compositionally — engaged + recent + has-tag — rather than one massive 12-clause query. Smaller segments are easier to debug when the count looks wrong.", category: "Marketing", keywords: "segments dynamic static frozen rules query recalculate freeze performance compositional debug", pages: ["/marketing/segments"] },
  { id: "mkt-15", title: "📜 Contact detail & activity timeline", body: "Every contact has a profile page summarising fields, tags, and a chronological activity timeline.\\n\\n## Opening a contact\\n\\nClick any row in **Marketing** → **Contacts**. The profile shows email, name, company, tags, custom fields, and source.\\n\\n## The timeline\\n\\nEvery interaction is logged: campaign sends, opens, clicks, replies, bounces, unsubscribe events, tag changes, sequence enrolments, and manual notes. Filter by event type with the dropdown above the timeline.\\n\\n## Editing\\n\\nUpdate fields inline, add or remove tags from the **Tags** chip-bar, and write notes in the **Notes** tab. Edits are stored without re-sending or notifying the contact.\\n\\n💡 Pro tip: Before replying to a prospect, scan their timeline for the last campaign they engaged with — referencing the exact email they opened lifts reply-to-meeting conversion noticeably.", category: "Marketing", keywords: "contact detail profile timeline activity events opens clicks replies bounces tags notes editing", pages: ["/marketing/contacts"] },
  { id: "mkt-16", title: "🔐 Domain authentication (SPF & DKIM)", body: "Authenticated domains land in inboxes; unauthenticated ones land in spam.\\n\\n## What SPF and DKIM do\\n\\n**SPF** tells receivers which servers are allowed to send mail for your domain. **DKIM** cryptographically signs every message so receivers can verify it wasn't tampered with in transit.\\n\\n## Setting them up\\n\\n**Marketing** → **Settings** → **Sender Identity** shows the exact TXT records to add to your DNS provider. Copy them in, save, and click **Verify** in CherryWorks.\\n\\n## Verifying it worked\\n\\nThe domain badge flips to green within minutes once DNS propagates. Until then, sends are blocked to protect your reputation.\\n\\n## DMARC\\n\\nA DMARC policy isn't required to send, but adding p=quarantine once SPF and DKIM are green lifts deliverability further.\\n\\n💡 Pro tip: After flipping SPF and DKIM green, send a test to a fresh Gmail account and inspect the Show Original view — both should show PASS. If either shows fail, your DNS isn't right yet.", category: "Marketing", keywords: "domain authentication SPF DKIM DMARC DNS TXT records verify deliverability inbox spam reputation", pages: ["/marketing"] },
  { id: "mkt-17", title: "🌡️ Warm-up & sending limits", body: "A brand-new sending domain has zero reputation. Warm-up builds it gradually so big sends don't get throttled or blocked.\\n\\n## Daily caps\\n\\nNew domains start at **50 sends/day** and step up by 50 each day for the first two weeks until reaching the plan limit. The cap is enforced in the worker — a campaign exceeding it splits across days.\\n\\n## Why it matters\\n\\nGmail and Outlook treat any domain that suddenly fires 10,000 emails as a spammer. Slow ramp-up signals legitimacy.\\n\\n## Plan limits\\n\\nBusiness: 25,000 sends/month. Enterprise: 250,000 sends/month with optional dedicated IP. Limits reset on the first of each month.\\n\\n💡 Pro tip: During warm-up, only send to your most engaged contacts (people who've opened recent transactional email). Strong opens and zero spam complaints accelerate the warm-up.", category: "Marketing", keywords: "warm-up sending limits daily cap domain reputation ramp Gmail Outlook plan business enterprise quota", pages: ["/marketing"] },
  { id: "mkt-18", title: "↩️ Bounces & retries", body: "Bounces happen — handling them right protects your sender reputation.\\n\\n## Hard vs soft\\n\\nA **hard bounce** means the address is permanently invalid (no such mailbox, domain doesn't exist). The contact is auto-suppressed after one hard bounce.\\n\\nA **soft bounce** is temporary (full mailbox, server timeout). The worker retries soft bounces three times over 24 hours before suppressing.\\n\\n## Where bounces show up\\n\\nCampaign **Recipients** view tags each bounced row with the type and the SMTP error. **Suppression** lists every auto-suppressed address with the reason and timestamp.\\n\\n## Bounce rate health\\n\\nKeep total bounce rate under 2%. Above 5% triggers warnings from inbox providers; above 10% your domain reputation collapses.\\n\\n💡 Pro tip: After every imported list, send a low-stakes welcome email first. Hard bounces flush out the bad addresses before your real campaign reaches scale.", category: "Marketing", keywords: "bounces retries hard soft suppression mailbox SMTP error bounce rate reputation deliverability welcome", pages: ["/marketing/activity"] },
  { id: "mkt-19", title: "🚫 Unsubscribes & suppression list", body: "Unsubscribes and suppressions both stop future sends — but for different reasons.\\n\\n## Unsubscribes\\n\\nEvery campaign automatically includes a CAN-SPAM-compliant unsubscribe link in the footer. Clicking it adds the contact to **Unsubscribed** instantly and they'll never receive marketing email from your org again.\\n\\n## Suppression list\\n\\n**Marketing** → **Suppression** lists every blocked address: hard bounces, complaint reports, manual additions, and unsubscribes. Each row shows the reason and date.\\n\\n## Manual suppression\\n\\nAdd an email manually when a contact requests pause-by-reply, when a deliverability issue is reported, or for legal compliance. Removal is one-click and reversible.\\n\\n## Per-org vs per-list\\n\\nSuppression is org-wide — once an address is suppressed, no campaign or sequence in your org can reach it.\\n\\n💡 Pro tip: Check suppression growth weekly. A sudden spike in unsubscribes after a campaign means the audience or content was wrong — pause before sending the next one.", category: "Marketing", keywords: "unsubscribes suppression CAN-SPAM compliance footer link blocked manual reversal org-wide growth spike", pages: ["/marketing"] },
  { id: "mkt-20", title: "💬 Replies & reply tracking", body: "Every campaign reply is captured and threaded so conversations don't get lost.\\n\\n## How replies are tracked\\n\\nThe Reply-To address on every send routes inbound mail through CherryWorks. Replies appear under the campaign's **Replies** tab and on the contact's timeline.\\n\\n## Notifications\\n\\nThe campaign owner gets an in-app notification (and an optional email digest) when a reply lands. Click through to read and respond inline — your response sends from your verified sender identity and is logged on the timeline.\\n\\n## Auto-tagging engaged repliers\\n\\nA contact who replies is auto-tagged with engaged-reply so you can build a follow-up segment of warm leads.\\n\\n💡 Pro tip: Reply to every inbound message within 4 hours during business days. Speed-of-reply correlates with meeting-booking rate more strongly than any subject-line tweak.", category: "Marketing", keywords: "replies reply tracking inbound conversation thread notification email digest auto-tag engaged warm leads", pages: ["/marketing/campaigns","/marketing/activity"] },
  { id: "mkt-21", title: "🔁 Sequence enrollment basics", body: "Sequences are multi-step drips — enrol a contact and they receive a chain of emails over days or weeks.\\n\\n## Building a sequence\\n\\n**Marketing** → **Sequences** → **New Sequence**. Add steps with a delay (e.g. send Day 0, Day 3, Day 7) and write each email like a campaign.\\n\\n## Enrolling contacts\\n\\nEnrol manually from a contact's profile, in bulk via tag or segment, or automatically via triggers (new-contact-with-tag-X, clicked-link-in-campaign-Y).\\n\\n## Stop conditions\\n\\nA sequence auto-pauses for a contact who replies, unsubscribes, or hits any rule you set (for example, stop if booked-meeting tag is added). No double-emailing.\\n\\n## Tracking\\n\\nEach sequence shows enrolled count, completed count, paused count, and per-step engagement.\\n\\n💡 Pro tip: Three-step sequences outperform 10-step sequences in B2B. Day 0 intro, Day 3 value-add, Day 7 ask — anything longer feels like spam to most prospects.", category: "Marketing", keywords: "sequences enrollment drip multi-step delay trigger stop condition tracking enrolled paused B2B", pages: ["/marketing/sequences"] },
  { id: "mkt-22", title: "🛠️ My campaign didn't send", body: "A campaign that fails to dispatch usually trips one of four checks. Run them in order.\\n\\n## 1. Sender identity verified?\\n\\n**Marketing** → **Settings** → **Sender Identity**. SPF and DKIM badges must be green. Red badges block all sends.\\n\\n## 2. Audience non-empty?\\n\\nOpen the campaign and confirm the audience count is greater than zero. A typo in a tag or a too-narrow segment commonly returns 0 recipients.\\n\\n## 3. Within plan limit?\\n\\nIf you've already sent your monthly quota, new campaigns sit in **Queued** until the limit resets on the 1st. Check **Settings** → **Subscription**.\\n\\n## 4. Activity firehose\\n\\nIf 1–3 are clean, open **Marketing** → **Activity** and filter by the campaign — you'll see the exact failure reason on each recipient row.\\n\\n💡 Pro tip: Send a fresh test to your own inbox after every failure diagnosis. Confirms the fix worked before you blast the real audience.", category: "Marketing", keywords: "campaign didn't send troubleshoot failure sender verified audience plan limit quota activity firehose diagnose", pages: ["/marketing/campaigns","/marketing/activity"] },
  { id: "mkt-23", title: "🔥 Activity firehose", body: "The Activity page is the per-send event log — every send, open, click, bounce, reply, and suppression in one chronological feed.\\n\\n## Where it is\\n\\n**Marketing** → **Activity**. Filter by event type (sent, delivered, opened, clicked, bounced, replied, unsubscribed, suppressed), by campaign, by sequence, by contact, or by date range.\\n\\n## When to use it\\n\\nDiagnosing a single email's fate: why didn't Sarah at Acme get my campaign? Filter by her email and you'll see the exact event chain — sent, soft-bounced, retried, hard-bounced, suppressed, with timestamps and SMTP responses.\\n\\n## Export\\n\\nClick **Export CSV** to pull the filtered view into a spreadsheet for reporting or audit.\\n\\n💡 Pro tip: When deliverability looks weird, filter Activity to event = bounced for the last 7 days and group by domain. A spike of bounces from one domain (e.g. a corporate firewall) is solvable; a flat spike across all domains is a sender-reputation issue.", category: "Marketing", keywords: "activity firehose event log feed filter event type campaign sequence contact date range diagnose export CSV", pages: ["/marketing/activity"] },
];
